    14→fn resolve_states(state_filter: &str) -> Vec<&str> {
    15→    match state_filter {
    16→        "all" => vec!["drafts", "pending", "running", "done", "failed", "merged"],
    17→        "active" => vec!["pending", "running", "done"],
    18→        "drafts" => vec!["drafts"],
    19→        other => vec![other],
    20→    }
    21→}
