    23→/// Summary statistics for cards in the workspace.
    24→pub struct CardStats {
    25→    pub total: usize,
    26→    pub by_state: HashMap<String, usize>,
    27→    pub avg_duration_s: Option<f64>,
    28→    pub success_rate_pct: Option<f64>,
    29→}
    30→
    31→/// Calculate statistics: count cards by state and compute average duration.
    32→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    33→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    34→    let mut by_state = HashMap::new();
    35→    let mut total = 0;
    36→    let mut durations = Vec::new();
    37→
    38→    for state in &states {
    39→        // Process root-level state directory
    40→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    41→
    42→        // Process team-* directories
    43→        if let Ok(entries) = fs::read_dir(root) {
    44→            for entry in entries.flatten() {
    45→                let team_path = entry.path();
    46→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    47→                    collect_state_stats(
    48→                        &team_path,
    49→                        state,
    50→                        &mut by_state,
    51→                        &mut total,
    52→                        &mut durations,
    53→                    )?;
    54→                }
    55→            }
    56→        }
    57→    }
    58→
    59→    let avg_duration_s = if durations.is_empty() {
    60→        None
    61→    } else {
    62→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    63→    };
    64→
    65→    let success_rate_pct = {
    66→        let done = by_state.get("done").copied().unwrap_or(0);
    67→        let failed = by_state.get("failed").copied().unwrap_or(0);
    68→        if done + failed > 0 {
    69→            Some((done as f64 / (done + failed) as f64) * 100.0)
    70→        } else {
    71→            None
    72→        }
    73→    };
    74→
    75→    Ok(CardStats {
    76→        total,
    77→        by_state,
    78→        avg_duration_s,
    79→        success_rate_pct,
    80→    })
    81→}
    82→
    83→fn collect_state_stats(
    84→    dir: &Path,
    85→    state: &str,
    86→    by_state: &mut HashMap<String, usize>,
    87→    total: &mut usize,
    88→    durations: &mut Vec<f64>,
    89→) -> anyhow::Result<()> {
    90→    let state_dir = dir.join(state);
    91→    if !state_dir.exists() {
    92→        return Ok(());
    93→    }
    94→
    95→    let Ok(entries) = fs::read_dir(&state_dir) else {
    96→        return Ok(());
    97→    };
    98→
    99→    for entry in entries.flatten() {
   100→        let path = entry.path();
   101→        if path.is_dir()
   102→            && path
   103→                .extension()
   104→                .is_some_and(|e| e == "bop" || e == "jobcard")
   105→        {
   106→            if let Ok(meta) = bop_core::read_meta(&path) {
   107→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   108→                *total += 1;
   109→
   110→                // Collect duration from last run if available
   111→                if let Some(last_run) = meta.runs.last() {
   112→                    if let Some(dur) = last_run.duration_s {
   113→                        durations.push(dur as f64);
   114→                    }
   115→                }
   116→            }
   117→        }
   118→    }
   119→
   120→    Ok(())
   121→}
