   200→/// Count lines for a single state group (header + cards + blank line).
   201→fn count_state_group_lines(dir: &Path, state: &str) -> anyhow::Result<usize> {
   202→    let state_dir = dir.join(state);
   203→    if !state_dir.exists() {
   204→        return Ok(0);
   205→    }
   206→
   207→    let mut card_count = 0;
   208→    if let Ok(entries) = fs::read_dir(&state_dir) {
   209→        for entry in entries.flatten() {
   210→            let p = entry.path();
   211→            if p.is_dir()
   212→                && p.extension().is_some_and(|e| e == "bop" || e == "jobcard")
   213→                && bop_core::read_meta(&p).is_ok()
   214→            {
   215→                card_count += 1;
   216→            }
   217→        }
   218→    }
   219→
   220→    if card_count == 0 {
   221→        return Ok(0);
   222→    }
   223→
   224→    // header + cards + blank line
   225→    Ok(1 + card_count + 1)
   226→}
