     6→pub fn card_state_from_path(card_dir: &Path) -> Option<String> {
     7→    card_dir
     8→        .parent()
     9→        .and_then(|p| p.file_name())
    10→        .and_then(|s| s.to_str())
    11→        .map(|s| s.to_string())
    12→}
