    14→pub fn infer_card_id_from_path(card_dir: &Path) -> Option<String> {
    15→    let name = card_dir.file_name()?.to_str()?;
    16→    let base = name.strip_suffix(".bop").unwrap_or(name);
    17→    Some(base.to_string())
    18→}
