   114→pub fn render_card_thumbnail(card_dir: &Path) {
   115→    sync_card_action_links(card_dir);
   116→
   117→    if !cfg!(target_os = "macos") {
   118→        return;
   119→    }
   120→    let meta = card_dir.join("meta.json");
   121→    if !meta.exists() {
   122→        return;
   123→    }
   124→    let ql_dir = card_dir.join("QuickLook");
   125→    let _ = fs::create_dir_all(&ql_dir);
   126→    let out = ql_dir.join("Thumbnail.png");
   127→    let Some(script) = util::find_repo_script(card_dir, "scripts/render_card_thumbnail.swift")
   128→    else {
   129→        return;
   130→    };
   131→
   132→    let _ = StdCommand::new("swift")
   133→        .arg(script)
   134→        .arg(&meta)
   135→        .arg(out)
   136→        .status();
   137→
   138→    // Update Finder folder icon: stage colour + glyph, set on every state transition
   139→    if let Some(icon_script) = util::find_repo_script(card_dir, "scripts/set_card_icon.swift") {
   140→        let _ = StdCommand::new("swift")
   141→            .arg(icon_script)
   142→            .arg(card_dir)
   143→            .status();
   144→    }
   145→
   146→    compress_card(card_dir);
   147→}
