    20→pub fn write_webloc(path: &Path, target_url: &str) -> anyhow::Result<()> {
    21→    let body = format!(
    22→        r#"<?xml version="1.0" encoding="UTF-8"?>
    23→<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
    24→<plist version="1.0">
    25→<dict>
    26→  <key>URL</key>
    27→  <string>{target_url}</string>
    28→</dict>
    29→</plist>
    30→"#
    31→    );
    32→    fs::write(path, body)?;
    33→    Ok(())
    34→}
    35→
    36→fn push_pct_encoded_byte(out: &mut String, byte: u8) {
    37→    const HEX: &[u8; 16] = b"0123456789ABCDEF";
    38→    out.push('%');
    39→    out.push(char::from(HEX[(byte >> 4) as usize]));
    40→    out.push(char::from(HEX[(byte & 0x0F) as usize]));
    41→}
    42→
    43→fn encode_bop_path_segment(segment: &str) -> String {
    44→    let mut out = String::with_capacity(segment.len());
    45→    for &byte in segment.as_bytes() {
    46→        let is_unreserved =
    47→            byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b'.' | b'_' | b'~');
    48→        if is_unreserved {
    49→            out.push(byte as char);
    50→        } else {
    51→            push_pct_encoded_byte(&mut out, byte);
    52→        }
    53→    }
    54→    out
    55→}
    56→
    57→fn bop_card_url(card_id: &str, action: &str) -> String {
    58→    format!(
    59→        "bop://card/{}/{}",
    60→        encode_bop_path_segment(card_id),
    61→        encode_bop_path_segment(action),
    62→    )
    63→}
