    65→pub fn sync_card_action_links(card_dir: &Path) {
    66→    let meta = bop_core::read_meta(card_dir).ok();
    67→    let id = meta
    68→        .as_ref()
    69→        .map(|m| m.id.clone())
    70→        .or_else(|| infer_card_id_from_path(card_dir))
    71→        .unwrap_or_default();
    72→    if id.trim().is_empty() {
    73→        return;
    74→    }
    75→
    76→    let state = card_state_from_path(card_dir).unwrap_or_else(|| "unknown".to_string());
    77→    let done_like = matches!(state.as_str(), "done" | "merged" | "failed");
    78→    let logs_action = if done_like { "logs" } else { "tail" };
    79→    let logs_url = bop_card_url(&id, logs_action);
    80→    let logs_label = if done_like { "Open logs" } else { "Tail logs" };
    81→    let logs_cmd = if done_like {
    82→        format!("bop logs {id}")
    83→    } else {
    84→        format!("bop logs {id} --follow")
    85→    };
    86→
    87→    let session = meta
    88→        .as_ref()
    89→        .and_then(|m| m.zellij_session.as_ref())
    90→        .map(|s| s.trim())
    91→        .filter(|s| !s.is_empty())
    92→        .map(|s| s.to_string());
    93→
    94→    let mut links_md = String::from("# Card Links\n\n");
    95→    links_md.push_str(&format!("- Logs: [{logs_label}]({logs_url})\n"));
    96→    links_md.push_str(&format!("- Logs command: `{logs_cmd}`\n"));
    97→
    98→    let session_webloc = card_dir.join("Session.webloc");
    99→    if let Some(session) = session {
   100→        let session_url = bop_card_url(&id, "session");
   101→        links_md.push_str(&format!("- Session: [Attach zellij]({session_url})\n"));
   102→        links_md.push_str(&format!(
   103→            "- Session command: `zellij attach {session} 2>/dev/null || zellij -s {session}`\n"
   104→        ));
   105→        let _ = write_webloc(&session_webloc, &session_url);
   106→    } else {
   107→        let _ = fs::remove_file(&session_webloc);
   108→    }
   109→
   110→    let _ = fs::write(card_dir.join("links.md"), links_md);
   111→    let _ = write_webloc(&card_dir.join("Logs.webloc"), &logs_url);
   112→}
