    10→/// Run set_card_icon.swift on a single path (card bundle or state dir).
    11→pub fn set_card_icon(path: &Path) {
    12→    if !cfg!(target_os = "macos") {
    13→        return;
    14→    }
    15→    if let Some(script) = util::find_repo_script(path, "scripts/set_card_icon.swift") {
