    19→
    20→/// Stamp icons for all state dirs + cards within a single team root.
    21→/// Terminal-state cards also get compression refreshed.
    22→pub fn sync_icons_in_root(
    23→    team_root: &Path,
    24→    n_cards: &mut usize,
    25→    n_dirs: &mut usize,
    26→    n_terminal_cards: &mut usize,
    27→) {
    28→    const STATES: &[&str] = &[
    29→        "drafts",
    30→        "pending",
    31→        "running",
    32→        "done",
    33→        "merged",
    34→        "failed",
    35→        "templates",
    36→    ];
    37→    for &state in STATES {
    38→        let dir = team_root.join(state);
    39→        if !dir.exists() {
    40→            continue;
    41→        }
    42→        // State directory itself gets an icon.
    43→        set_card_icon(&dir);
    44→        *n_dirs += 1;
    45→        // Each .bop inside gets an icon.
    46→        if let Ok(entries) = fs::read_dir(&dir) {
    47→            for entry in entries.flatten() {
    48→                let path = entry.path();
    49→                if path.extension().and_then(|e| e.to_str()) == Some("bop") && path.is_dir() {
    50→                    set_card_icon(&path);
    51→                    quicklook::sync_card_action_links(&path);
    52→                    if matches!(
    53→                        quicklook::card_state_from_path(&path).as_deref(),
    54→                        Some("done" | "failed" | "merged")
    55→                    ) {
    56→                        quicklook::compress_card(&path);
    57→                        *n_terminal_cards += 1;
    58→                    }
    59→                    *n_cards += 1;
    60→                }
    61→            }
    62→        }
    63→    }
    64→}
    65→
    66→/// Batch: update icons for every state dir + .bop under .cards/.
    67→pub fn cmd_icons_sync(root: &Path) -> anyhow::Result<()> {
    68→    if !cfg!(target_os = "macos") {
    69→        println!("icons: macOS only");
    70→        return Ok(());
    71→    }
    72→    let mut n_cards = 0usize;
    73→    let mut n_dirs = 0usize;
    74→    let mut n_terminal_cards = 0usize;
    75→
    76→    // Top-level state dirs
    77→    sync_icons_in_root(root, &mut n_cards, &mut n_dirs, &mut n_terminal_cards);
    78→
    79→    // team-* subdirs
    80→    for entry in fs::read_dir(root)? {
    81→        let team = entry?.path();
    82→        if team.is_dir()
    83→            && team
    84→                .file_name()
    85→                .and_then(|n| n.to_str())
    86→                .map(|n| n.starts_with("team-"))
    87→                .unwrap_or(false)
    88→        {
    89→            sync_icons_in_root(&team, &mut n_cards, &mut n_dirs, &mut n_terminal_cards);
    90→        }
    91→    }
    92→    println!(
    93→        "✓ icons synced: {} state dirs, {} cards ({} terminal cards compression-refreshed)",
    94→        n_dirs, n_cards, n_terminal_cards
    95→    );
    96→    Ok(())
    97→}
