   152→/// Install a launchd WatchPaths agent: fires `bop icons sync` whenever .cards/ changes.
   153→pub fn cmd_icons_install(root: &Path) -> anyhow::Result<()> {
   154→    #[cfg(not(target_os = "macos"))]
   155→    {
   156→        println!("icons install: macOS only");
   157→        return Ok(());
   158→    }
   159→
   160→    let bop_bin = std::env::current_exe().unwrap_or_else(|_| PathBuf::from("/usr/local/bin/bop"));
   161→    let cards_dir = root.to_string_lossy().to_string();
   162→
   163→    let plist = format!(
   164→        r#"<?xml version="1.0" encoding="UTF-8"?>
   165→<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN"
   166→  "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
   167→<plist version="1.0">
   168→<dict>
   169→  <key>Label</key>
   170→  <string>{label}</string>
   171→
   172→  <key>WatchPaths</key>
   173→  <array>
   174→    <string>{cards}</string>
   175→  </array>
   176→
   177→  <key>ProgramArguments</key>
   178→  <array>
   179→    <string>{bop}</string>
   180→    <string>--cards-root</string>
   181→    <string>{cards}</string>
   182→    <string>icons</string>
   183→    <string>sync</string>
   184→  </array>
   185→
   186→  <key>StandardOutPath</key>
   187→  <string>/tmp/bop-iconwatcher.log</string>
   188→
   189→  <key>StandardErrorPath</key>
   190→  <string>/tmp/bop-iconwatcher.err</string>
   191→</dict>
   192→</plist>
   193→"#,
   194→        label = ICONS_LABEL,
   195→        cards = cards_dir,
   196→        bop = bop_bin.display(),
   197→    );
   198→
   199→    let dest = plist_path(ICONS_LABEL);
   200→    fs::write(&dest, &plist)?;
   201→
   202→    let _ = StdCommand::new("launchctl")
   203→        .args(["unload", "-w"])
   204→        .arg(&dest)
   205→        .output();
   206→    let status = StdCommand::new("launchctl")
   207→        .args(["load", "-w"])
   208→        .arg(&dest)
   209→        .status()?;
   210→
   211→    if status.success() {
   212→        println!("✓ icon watcher installed: {}", dest.display());
   213→        println!("  Fires `bop icons sync` whenever .cards/ changes.");
   214→        println!("  Logs: /tmp/bop-iconwatcher.log");
   215→        println!("\n  To remove: bop icons uninstall");
   216→    } else {
   217→        anyhow::bail!("launchctl load failed");
   218→    }
   219→    Ok(())
   220→}
