    10→struct Bar {
    11→    id: String,
    12→    glyph: String,
    13→    state: String,
    14→    stage: String,
    15→    provider: String,
    16→    start: DateTime<Utc>,
    17→    end: DateTime<Utc>,
    18→    dur_s: f64,
    19→    tokens: Option<u64>,
    20→    cost: Option<f64>,
    21→}
    22→
    23→fn parse_ts(s: &str) -> Option<DateTime<Utc>> {
    24→    // Try standard ISO, then strip Z and retry
    25→    if let Ok(dt) = s.parse::<DateTime<Utc>>() {
    26→        return Some(dt);
    27→    }
    28→    // chrono's parse with flexible format
    29→    chrono::NaiveDateTime::parse_from_str(s.trim_end_matches('Z'), "%Y-%m-%dT%H:%M:%S")
    30→        .ok()
    31→        .map(|n| n.and_utc())
    32→}
    33→
    34→fn collect_bars(root: &Path) -> Vec<Bar> {
    35→    let states = ["running", "done", "merged", "failed", "pending"];
    36→    let mut bars = Vec::new();
    37→
    38→    for state in &states {
    39→        let dir = root.join(state);
    40→        if !dir.exists() {
    41→            continue;
    42→        }
    43→        let Ok(entries) = fs::read_dir(&dir) else {
    44→            continue;
    45→        };
    46→        for entry in entries.flatten() {
    47→            let path = entry.path();
    48→            if path.extension().and_then(|e| e.to_str()) != Some("bop") {
    49→                continue;
    50→            }
    51→            let Ok(meta) = bop_core::read_meta(&path) else {
    52→                continue;
    53→            };
    54→            let Some(last_run) = meta.runs.last() else {
    55→                continue;
    56→            };
    57→            let Some(start) = parse_ts(&last_run.started_at) else {
    58→                continue;
    59→            };
    60→
    61→            let end = last_run
    62→                .ended_at
    63→                .as_deref()
    64→                .and_then(parse_ts)
    65→                .unwrap_or_else(|| {
    66→                    // Cap open-ended: use duration_s or 10 min
    67→                    let dur = last_run.duration_s.unwrap_or(0) as i64;
    68→                    if dur > 0 {
    69→                        start + Duration::seconds(dur)
    70→                    } else {
    71→                        start + Duration::minutes(10)
    72→                    }
    73→                });
    74→
    75→            let dur_s = (end - start).num_milliseconds() as f64 / 1000.0;
    76→            if dur_s < 2.0 {
    77→                continue;
    78→            }
    79→
    80→            let tokens = match (last_run.prompt_tokens, last_run.completion_tokens) {
    81→                (Some(p), Some(c)) => Some(p + c),
    82→                (Some(p), None) => Some(p),
    83→                (None, Some(c)) => Some(c),
    84→                _ => None,
    85→            };
    86→
    87→            bars.push(Bar {
    88→                id: meta.id.clone(),
    89→                glyph: meta.glyph.or(meta.token).unwrap_or_default(),
    90→                state: state.to_string(),
    91→                stage: meta.stage.clone(),
    92→                provider: last_run.provider.clone(),
    93→                start,
    94→                end,
    95→                dur_s,
    96→                tokens,
    97→                cost: last_run.cost_usd,
    98→            });
    99→        }
   100→    }
   101→
   102→    bars.sort_by_key(|b| b.start);
   103→    bars
   104→}
   105→
   106→/// Cluster bars: gap > 30 min = new cluster.
   107→fn cluster(bars: &[Bar]) -> Vec<Vec<usize>> {
   108→    if bars.is_empty() {
   109→        return Vec::new();
   110→    }
   111→    let mut clusters: Vec<Vec<usize>> = vec![vec![0]];
   112→    for i in 1..bars.len() {
   113→        let prev_end = bars[clusters.last().unwrap().iter().copied().fold(0, |best, j| {
   114→            if bars[j].end > bars[best].end {
   115→                j
   116→            } else {
   117→                best
   118→            }
   119→        })]
   120→        .end;
   121→        if (bars[i].start - prev_end).num_seconds() > 1800 {
   122→            clusters.push(vec![i]);
   123→        } else {
   124→            clusters.last_mut().unwrap().push(i);
   125→        }
   126→    }
   127→    clusters
   128→}
   129→
   130→fn dur_label(s: f64) -> String {
   131→    if s >= 60.0 {
   132→        format!("{:.1}m", s / 60.0)
   133→    } else {
   134→        format!("{:.0}s", s)
   135→    }
   136→}
   137→
   138→// ── ANSI terminal rendering ─────────────────────────────────────────────────
   139→
   140→fn render_ansi(bars: &[Bar], term_width: usize) {
   141→    let clusters = cluster(bars);
   142→    let label_width = 24_usize;
   143→    let dur_width = 7_usize;
   144→    // bar_cols = total width - label - " │ " (3) - " " (1) - dur_label - " " (1)
   145→    let bar_cols = term_width
   146→        .saturating_sub(label_width + 3 + dur_width + 2)
   147→        .max(20);
   148→
   149→    // Header
   150→    println!(
   151→        "{}bop · agent timeline{} {} — {} runs{}",
   152→        BOLD,
   153→        RESET,
   154→        DIM,
   155→        bars.len(),
   156→        RESET
   157→    );
   158→    println!();
   159→
   160→    for indices in &clusters {
   161→        let c_min = indices.iter().map(|&i| bars[i].start).min().unwrap();
   162→        let c_max = indices.iter().map(|&i| bars[i].end).max().unwrap();
   163→        let c_span = (c_max - c_min).num_seconds().max(1) as f64;
   164→
   165→        // Cluster header
   166→        println!(
   167→            "{}{} — {} · {} runs{}",
   168→            DIM,
   169→            c_min.format("%b %d, %H:%M"),
