   178→            axis.push(' ');
   179→        }
   180→        axis.push_str(" │ ");
   181→
   182→        // Place time labels on the axis
   183→        let mut axis_chars: Vec<char> = vec![' '; bar_cols];
   184→        // We'll place a few evenly-spaced time markers
   185→        let n_marks = (bar_cols / 15).clamp(2, 8);
   186→        for m in 0..n_marks {
   187→            let frac = m as f64 / (n_marks - 1).max(1) as f64;
   188→            let col = (frac * (bar_cols - 5) as f64) as usize;
   189→            let t = c_min + Duration::milliseconds((frac * c_span * 1000.0) as i64);
   190→            let label = t.format("%H:%M").to_string();
   191→            for (j, ch) in label.chars().enumerate() {
   192→                if col + j < bar_cols {
   193→                    axis_chars[col + j] = ch;
   194→                }
   195→            }
   196→        }
   197→        let axis_str: String = axis_chars.into_iter().collect();
   198→        println!("{}{}{}{}", axis, DIM, axis_str, RESET);
   199→
   200→        // Separator
   201→        let mut sep = String::with_capacity(label_width + 3 + bar_cols);
   202→        for _ in 0..label_width {
   203→            sep.push(' ');
   204→        }
   205→        sep.push_str(" ├─");
   206→        for _ in 0..bar_cols {
   207→            sep.push('─');
   208→        }
   209→        println!("{}{}{}", DIM, sep, RESET);
   210→
   211→        // Bars
   212→        for &i in indices {
   213→            let b = &bars[i];
   214→
   215→            // Label: glyph + truncated id
   216→            let mut label = String::with_capacity(label_width);
