     1→//! Real-time data feed integration for bop.
     2→//!
     3→//! Provides types and utilities for ingesting, validating, and monitoring
     4→//! real-time data streams from IoT sensors, GPS devices, and HTTP endpoints.
     5→//!
     6→//! # Example
     7→//!
     8→//! ```rust
     9→//! use bop_core::realtime::{
    10→//!     FeedConfig, FeedSourceType, ValidationConfig, ValueRange, FeedHealth,
    11→//!     validate_record, FeedMetrics, example_gps_record,
    12→//! };
    13→//! use std::collections::HashMap;
    14→//!
    15→//! let mut ranges = HashMap::new();
    16→//! ranges.insert("latitude".to_string(), ValueRange { min: -90.0, max: 90.0 });
    17→//! ranges.insert("longitude".to_string(), ValueRange { min: -180.0, max: 180.0 });
    18→//!
    19→//! let config = FeedConfig {
    20→//!     id: "gps-fleet-01".to_string(),
    21→//!     source_type: FeedSourceType::Gps,
    22→//!     endpoint: "udp://0.0.0.0:5005".to_string(),
    23→//!     poll_interval_secs: 10,
    24→//!     validation: ValidationConfig {
    25→//!         required_fields: vec!["latitude".to_string(), "longitude".to_string()],
    26→//!         max_staleness_secs: 60,
    27→//!         value_ranges: ranges,
    28→//!     },
    29→//! };
    30→//!
    31→//! let record = example_gps_record("gps-fleet-01", 37.7749, -122.4194, 60.0);
    32→//! let result = validate_record(&record, &config);
    33→//! assert!(result.valid);
    34→//!
    35→//! let mut metrics = FeedMetrics::new("gps-fleet-01".to_string());
    36→//! metrics.record_received(result.valid);
    37→//! assert_eq!(metrics.health, FeedHealth::Healthy);
    38→//! ```
    39→
    40→use chrono::{DateTime, Utc};
    41→use serde::{Deserialize, Serialize};
    42→use std::collections::HashMap;
    43→
    44→/// Configuration for a real-time data feed source.
    45→#[derive(Debug, Clone, Serialize, Deserialize)]
    46→pub struct FeedConfig {
    47→    /// Unique identifier for this feed.
    48→    pub id: String,
    49→    /// The type of data source.
    50→    pub source_type: FeedSourceType,
    51→    /// Connection endpoint (URL, socket address, or file path).
    52→    pub endpoint: String,
    53→    /// How often to poll the source, in seconds.
    54→    pub poll_interval_secs: u64,
    55→    /// Validation rules applied to incoming records.
    56→    pub validation: ValidationConfig,
    57→}
    58→
    59→/// Supported real-time data source types.
    60→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
    61→#[serde(rename_all = "snake_case")]
    62→pub enum FeedSourceType {
    63→    /// GPS or GNSS position feed.
    64→    Gps,
    65→    /// Generic IoT sensor feed.
    66→    Iot,
    67→    /// HTTP/HTTPS polling endpoint.
    68→    Http,
    69→    /// Local file updated by an external process.
    70→    File,
    71→}
    72→
    73→/// Validation rules for incoming feed records.
    74→#[derive(Debug, Clone, Serialize, Deserialize)]
    75→pub struct ValidationConfig {
    76→    /// Fields that must be present in every record.
    77→    pub required_fields: Vec<String>,
    78→    /// Maximum allowed age of a record in seconds before it is considered stale.
    79→    pub max_staleness_secs: u64,
    80→    /// Optional numeric range constraints keyed by field name.
    81→    pub value_ranges: HashMap<String, ValueRange>,
    82→}
    83→
    84→/// Inclusive numeric range `[min, max]` for a field value.
    85→#[derive(Debug, Clone, Serialize, Deserialize)]
    86→pub struct ValueRange {
    87→    /// Minimum acceptable value (inclusive).
    88→    pub min: f64,
    89→    /// Maximum acceptable value (inclusive).
    90→    pub max: f64,
    91→}
    92→
    93→/// A single record received from a data feed.
    94→#[derive(Debug, Clone, Serialize, Deserialize)]
    95→pub struct FeedRecord {
    96→    /// The feed this record belongs to.
    97→    pub feed_id: String,
    98→    /// When the record was produced by the source.
    99→    pub timestamp: DateTime<Utc>,
   100→    /// Payload key-value pairs.
   101→    pub fields: HashMap<String, serde_json::Value>,
   102→}
   103→
   104→/// Outcome of validating a [`FeedRecord`] against a [`FeedConfig`].
   105→#[derive(Debug, Clone)]
   106→pub struct ValidationResult {
   107→    /// Whether the record passed all validation rules.
   108→    pub valid: bool,
   109→    /// Human-readable descriptions of every rule that failed.
   110→    pub errors: Vec<String>,
   111→}
   112→
   113→impl ValidationResult {
   114→    /// Creates a successful result with no errors.
   115→    pub fn ok() -> Self {
   116→        Self {
   117→            valid: true,
   118→            errors: vec![],
   119→        }
   120→    }
   121→
   122→    /// Creates a failed result with the given error messages.
   123→    pub fn err(errors: Vec<String>) -> Self {
   124→        Self {
   125→            valid: false,
   126→            errors,
   127→        }
   128→    }
   129→}
   130→
   131→/// Validate `record` against the rules in `config`.
   132→///
   133→/// Checks performed:
   134→/// 1. All [`ValidationConfig::required_fields`] are present.
   135→/// 2. All numeric fields listed in [`ValidationConfig::value_ranges`] fall within
   136→///    their declared ranges.
   137→/// 3. The record's [`FeedRecord::timestamp`] is not older than
   138→///    [`ValidationConfig::max_staleness_secs`].
   139→pub fn validate_record(record: &FeedRecord, config: &FeedConfig) -> ValidationResult {
   140→    let mut errors = Vec::new();
   141→
   142→    // 1. Required fields
   143→    for field in &config.validation.required_fields {
   144→        if !record.fields.contains_key(field) {
   145→            errors.push(format!("missing required field: {field}"));
   146→        }
   147→    }
   148→
   149→    // 2. Value ranges
   150→    for (field, range) in &config.validation.value_ranges {
   151→        if let Some(value) = record.fields.get(field) {
   152→            if let Some(n) = value.as_f64() {
   153→                if n < range.min || n > range.max {
   154→                    errors.push(format!(
   155→                        "field '{field}' value {n} out of range [{}, {}]",
   156→                        range.min, range.max
   157→                    ));
   158→                }
   159→            }
   160→        }
   161→    }
   162→
   163→    // 3. Staleness
   164→    let age_secs = (Utc::now() - record.timestamp).num_seconds().unsigned_abs();
   165→    if age_secs > config.validation.max_staleness_secs {
   166→        errors.push(format!(
   167→            "record is stale: {age_secs}s old (max {}s allowed)",
   168→            config.validation.max_staleness_secs
   169→        ));
   170→    }
   171→
   172→    if errors.is_empty() {
   173→        ValidationResult::ok()
   174→    } else {
   175→        ValidationResult::err(errors)
   176→    }
   177→}
