   179→/// Overall health state of a feed, derived from its error rate.
   180→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
   181→#[serde(rename_all = "snake_case")]
   182→pub enum FeedHealth {
   183→    /// Error rate < 5 %.
   184→    Healthy,
   185→    /// Error rate between 5 % and 25 %.
   186→    Degraded,
   187→    /// No data received yet, or error rate ≥ 25 %.
   188→    Down,
   189→}
