   191→/// Rolling metrics for a single feed.
   192→#[derive(Debug, Clone, Serialize, Deserialize)]
   193→pub struct FeedMetrics {
   194→    /// Feed identifier.
   195→    pub feed_id: String,
   196→    /// Total records received since the metrics object was created.
   197→    pub records_received: u64,
   198→    /// Records that passed validation.
   199→    pub records_valid: u64,
   200→    /// Records that failed validation.
   201→    pub records_invalid: u64,
   202→    /// Timestamp of the most recent record, if any.
   203→    pub last_received: Option<DateTime<Utc>>,
   204→    /// Derived health status.
   205→    pub health: FeedHealth,
   206→}
   207→
   208→impl FeedMetrics {
   209→    /// Creates a fresh metrics object for the given feed.
   210→    pub fn new(feed_id: String) -> Self {
   211→        Self {
   212→            feed_id,
   213→            records_received: 0,
   214→            records_valid: 0,
   215→            records_invalid: 0,
   216→            last_received: None,
   217→            health: FeedHealth::Down,
   218→        }
   219→    }
   220→
   221→    /// Records that one record was received and updates health.
   222→    pub fn record_received(&mut self, valid: bool) {
   223→        self.records_received += 1;
   224→        self.last_received = Some(Utc::now());
   225→        if valid {
   226→            self.records_valid += 1;
   227→        } else {
   228→            self.records_invalid += 1;
   229→        }
   230→        self.update_health();
   231→    }
   232→
   233→    /// Fraction of records that passed validation (`0.0`–`1.0`).
   234→    pub fn success_rate(&self) -> f64 {
   235→        if self.records_received == 0 {
   236→            0.0
   237→        } else {
   238→            self.records_valid as f64 / self.records_received as f64
   239→        }
   240→    }
   241→
   242→    fn update_health(&mut self) {
   243→        let error_rate = if self.records_received == 0 {
   244→            1.0
   245→        } else {
   246→            self.records_invalid as f64 / self.records_received as f64
   247→        };
   248→
   249→        self.health = if error_rate < 0.05 {
   250→            FeedHealth::Healthy
   251→        } else if error_rate < 0.25 {
   252→            FeedHealth::Degraded
   253→        } else {
   254→            FeedHealth::Down
   255→        };
   256→    }
   257→}
