    20→pub fn write_webloc(path: &Path, target_url: &str) -> anyhow::Result<()> {
    21→    let body = format!(
    22→        r#"<?xml version="1.0" encoding="UTF-8"?>
    23→<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
    24→<plist version="1.0">
    25→<dict>
    26→  <key>URL</key>
    27→  <string>{target_url}</string>
