    35→
    36→fn push_pct_encoded_byte(out: &mut String, byte: u8) {
    37→    const HEX: &[u8; 16] = b"0123456789ABCDEF";
    38→    out.push('%');
    39→    out.push(char::from(HEX[(byte >> 4) as usize]));
    40→    out.push(char::from(HEX[(byte & 0x0F) as usize]));
    41→}
    42→
    43→fn encode_bop_path_segment(segment: &str) -> String {
    44→    let mut out = String::with_capacity(segment.len());
    45→    for &byte in segment.as_bytes() {
    46→        let is_unreserved =
    47→            byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b'.' | b'_' | b'~');
    48→        if is_unreserved {
    49→            out.push(byte as char);
    50→        } else {
    51→            push_pct_encoded_byte(&mut out, byte);
    52→        }
    53→    }
    54→    out
    55→}
