    57→fn bop_card_url(card_id: &str, action: &str) -> String {
    58→    format!(
    59→        "bop://card/{}/{}",
    60→        encode_bop_path_segment(card_id),
    61→        encode_bop_path_segment(action),
    62→    )
    63→}
