   149→pub fn compress_card(card_dir: &Path) {
   150→    if !cfg!(target_os = "macos") {
   151→        return;
   152→    }
   153→    let state = card_state_from_path(card_dir).unwrap_or_default();
   154→    if !matches!(state.as_str(), "done" | "failed" | "merged") {
   155→        return;
   156→    }
   157→
   158→    let Some(name) = card_dir.file_name().and_then(|s| s.to_str()) else {
   159→        return;
   160→    };
   161→    let Some(parent) = card_dir.parent() else {
   162→        return;
   163→    };
   164→    let compressed = parent.join(format!("{}.hfs.tmp", name));
   165→    let backup = parent.join(format!("{}.bak.tmp", name));
   166→    let _ = fs::remove_dir_all(&compressed);
   167→    let _ = fs::remove_dir_all(&backup);
   168→
   169→    let status = StdCommand::new("ditto")
   170→        .arg("--hfsCompression")
   171→        .arg(card_dir)
   172→        .arg(&compressed)
   173→        .status();
   174→    if !matches!(status, Ok(s) if s.success()) {
   175→        let _ = fs::remove_dir_all(&compressed);
   176→        return;
   177→    }
   178→
   179→    if fs::rename(card_dir, &backup).is_err() {
   180→        let _ = fs::remove_dir_all(&compressed);
   181→        return;
   182→    }
   183→    if fs::rename(&compressed, card_dir).is_err() {
   184→        let _ = fs::rename(&backup, card_dir);
   185→        let _ = fs::remove_dir_all(&compressed);
   186→        return;
   187→    }
   188→    let _ = fs::remove_dir_all(&backup);
   189→}
