    43→/// Read the last non-empty line from a log file and truncate to max_bytes.
    44→/// Returns None if the file doesn't exist or has no non-empty lines.
    45→pub fn read_last_nonempty_line(path: &Path, max_bytes: usize) -> Option<String> {
    46→    let content = fs::read_to_string(path).ok()?;
    47→    let last_line = content
    48→        .lines()
    49→        .rev()
    50→        .find(|line| !line.trim().is_empty())?
    51→        .to_string();
    52→
    53→    // Truncate to max_bytes if needed
    54→    if last_line.len() > max_bytes {
    55→        Some(last_line.chars().take(max_bytes).collect())
    56→    } else {
    57→        Some(last_line)
    58→    }
