    79→pub fn unique_failed_path(failed_dir: &Path, name: &str) -> PathBuf {
    80→    let direct = failed_dir.join(name);
    81→    if !direct.exists() {
    82→        return direct;
    83→    }
    84→    let stem = name.strip_suffix(".bop").unwrap_or(name);
    85→    let ts = Utc::now().timestamp_millis();
    86→    failed_dir.join(format!("{stem}-rejected-{ts}.bop"))
    87→}
