     1→//! Card character assignment: Team -> suit mapping, glyph allocation, and
     2→//! used-glyph collection from the `.cards/` filesystem.
     3→
     4→use std::collections::HashSet;
     5→use std::path::Path;
     6→
     7→/// Teams map 1:1 to playing-card suits.
     8→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
     9→pub enum Team {
    10→    /// Spades (U+1F0A0 base, BMP token U+2660)
    11→    Cli,
    12→    /// Hearts (U+1F0B0 base, BMP token U+2665)
    13→    Arch,
    14→    /// Diamonds (U+1F0C0 base, BMP token U+2666)
    15→    Quality,
    16→    /// Clubs (U+1F0D0 base, BMP token U+2663)
    17→    Platform,
    18→}
    19→
    20→impl Team {
    21→    /// SMP base codepoint for this suit (the "back" card, rank 0).
    22→    const fn smp_base(self) -> u32 {
    23→        match self {
    24→            Team::Cli => 0x1F0A0,
    25→            Team::Arch => 0x1F0B0,
    26→            Team::Quality => 0x1F0C0,
    27→            Team::Platform => 0x1F0D0,
    28→        }
    29→    }
    30→
    31→    /// BMP suit symbol used as the filename-safe token.
    32→    const fn bmp_token(self) -> char {
    33→        match self {
    34→            Team::Cli => '\u{2660}',      // BLACK SPADE SUIT
    35→            Team::Arch => '\u{2665}',     // BLACK HEART SUIT
    36→            Team::Quality => '\u{2666}',  // BLACK DIAMOND SUIT
    37→            Team::Platform => '\u{2663}', // BLACK CLUB SUIT
    38→        }
    39→    }
    40→}
    41→
    42→// ── Special cards (not auto-assigned) ────────────────────────────────────────
    43→
    44→/// Back of card — placeholder glyph before assignment.
    45→pub const CARD_BACK: char = '\u{1F0A0}'; // 🂠
    46→
    47→/// Jokers — emergency / wildcard / needs-breakdown.
    48→pub const RED_JOKER: char = '\u{1F0BF}'; // 🂿
    49→pub const BLACK_JOKER: char = '\u{1F0CF}'; // 🃏
    50→pub const WHITE_JOKER: char = '\u{1F0DF}'; // 🃟
    51→
    52→/// Trump cards (U+1F0E0..U+1F0F5) — cross-team escalation.
    53→/// Fool(0), then I(1)..XXI(21). 22 cards total.
    54→pub const TRUMP_FOOL: char = '\u{1F0E0}'; // 🃠
    55→pub const TRUMP_MAX: char = '\u{1F0F5}'; // 🃵
    56→/// Number of trump cards in the Unicode block.
    57→pub const TRUMP_COUNT: u32 = 22;
    58→
    59→/// All joker codepoints for quick membership checks.
    60→pub const JOKERS: [char; 3] = [RED_JOKER, BLACK_JOKER, WHITE_JOKER];
    61→
    62→/// Check whether a glyph char is a joker.
    63→pub fn is_joker(ch: char) -> bool {
    64→    JOKERS.contains(&ch)
    65→}
    66→
    67→/// Check whether a glyph char is a trump card (Fool through XXI).
    68→pub fn is_trump(ch: char) -> bool {
    69→    let cp = ch as u32;
    70→    cp >= TRUMP_FOOL as u32 && cp <= TRUMP_MAX as u32
    71→}
    72→
    73→// ── Trump BMP tokens ────────────────────────────────────────────────────────
    74→
    75→/// Return the (glyph, token) pair for a trump card by rank (0=Fool .. 21=World).
    76→///
    77→/// Glyph is the SMP character (U+1F0E0+rank).
    78→/// Token is a circled number in the BMP for terminal/filename display:
    79→///   rank 0  → ⓪ U+24FF
    80→///   rank 1–20 → ①–⑳ U+2460–U+2473
    81→///   rank 21 → ㉑ U+3251
    82→pub fn trump_glyph_and_token(rank: u32) -> Option<(char, char)> {
    83→    if rank > 21 {
    84→        return None;
    85→    }
    86→    let glyph = char::from_u32(0x1F0E0 + rank)?;
    87→    let token = match rank {
    88→        0 => '\u{24FF}',                          // ⓪
    89→        1..=20 => char::from_u32(0x245F + rank)?, // ①–⑳
    90→        21 => '\u{3251}',                         // ㉑
    91→        _ => unreachable!(),
    92→    };
    93→    Some((glyph, token))
    94→}
    95→
    96→// ── Auto-assignment ──────────────────────────────────────────────────────────
    97→
    98→/// Return the first unused (glyph, token) pair for `team`.
    99→///
   100→/// Walks ranks Ace(1) through King(14). Returns `None` when all 14 slots
   101→/// in the suit are occupied.
   102→pub fn next_glyph(team: Team, used: &HashSet<char>) -> Option<(String, String)> {
   103→    let base = team.smp_base();
   104→    for rank in 1..=14u32 {
   105→        let cp = base + rank;
   106→        let ch = char::from_u32(cp)?;
   107→        if !used.contains(&ch) {
   108→            return Some((String::from(ch), String::from(team.bmp_token())));
   109→        }
   110→    }
   111→    None
   112→}
   113→
   114→/// Detect the team from directory path components.
   115→///
   116→/// Scans for `team-cli`, `team-arch`, `team-quality`, `team-platform`.
   117→/// Defaults to `Team::Cli` when no team directory is found.
   118→pub fn team_from_path(path: &Path) -> Team {
   119→    for component in path.components() {
   120→        if let std::path::Component::Normal(os) = component {
   121→            if let Some(s) = os.to_str() {
   122→                match s {
   123→                    "team-cli" => return Team::Cli,
   124→                    "team-arch" => return Team::Arch,
   125→                    "team-quality" => return Team::Quality,
   126→                    "team-platform" => return Team::Platform,
   127→                    _ => {}
   128→                }
   129→            }
   130→        }
   131→    }
   132→    Team::Cli
   133→}
   134→
   135→/// Scan all card state directories under `cards_root` and collect the first
   136→/// character of every `glyph` field found in `meta.json`.
   137→///
   138→/// Scans both top-level state dirs (`pending/`, `running/`, `done/`, `failed/`)
   139→/// and team-scoped dirs (`team-*/pending/`, etc.).
   140→pub fn collect_used_glyphs(cards_root: &Path) -> HashSet<char> {
   141→    let mut used = HashSet::new();
   142→    let state_dirs = ["pending", "running", "done", "failed"];
   143→
   144→    // Collect from a single state directory
   145→    let mut scan_state_dir = |dir: &Path| {
   146→        if let Ok(entries) = std::fs::read_dir(dir) {
   147→            for entry in entries.flatten() {
   148→                let path = entry.path();
   149→                if path.is_dir()
   150→                    && path
   151→                        .file_name()
   152→                        .and_then(|n| n.to_str())
   153→                        .is_some_and(|n| n.ends_with(".bop"))
   154→                {
   155→                    if let Ok(meta) = crate::read_meta(&path) {
   156→                        if let Some(glyph) = &meta.glyph {
   157→                            if let Some(ch) = glyph.chars().next() {
   158→                                used.insert(ch);
   159→                            }
   160→                        }
   161→                    }
   162→                }
   163→            }
   164→        }
   165→    };
   166→
   167→    // Top-level state dirs
   168→    for state in &state_dirs {
   169→        scan_state_dir(&cards_root.join(state));
   170→    }
   171→
   172→    // Team-scoped dirs: team-*/state/
   173→    if let Ok(entries) = std::fs::read_dir(cards_root) {
   174→        for entry in entries.flatten() {
   175→            let path = entry.path();
   176→            if path.is_dir() {
   177→                if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
   178→                    if name.starts_with("team-") {
   179→                        for state in &state_dirs {
   180→                            scan_state_dir(&path.join(state));
   181→                        }
   182→                    }
   183→                }
   184→            }
   185→        }
   186→    }
   187→
   188→    used
   189→}
