  1→use std::collections::BTreeMap;
  2→use zellij_tile::prelude::*;
  3→
  4→#[derive(Default)]
  5→struct BopPlugin {
  6→    /// team_name → (running, pending, done_or_merged, failed)
  7→    counts: BTreeMap<String, (usize, usize, usize, usize)>,
  8→    cards_dir: String,
  9→}
 10→
 11→register_plugin!(BopPlugin);
 12→
 13→impl ZellijPlugin for BopPlugin {
 14→    fn load(&mut self, configuration: BTreeMap<String, String>) {
 15→        self.cards_dir = configuration
 16→            .get("cards_dir")
 17→            .cloned()
 18→            .unwrap_or_else(|| ".cards".to_string());
 19→        subscribe(&[EventType::Timer]);
 20→        set_timeout(2.0);
 21→        self.refresh_counts();
 22→    }
 23→
 24→    fn update(&mut self, event: Event) -> bool {
 25→        if let Event::Timer(_) = event {
 26→            self.refresh_counts();
 27→            set_timeout(2.0);
 28→            return true;
 29→        }
 30→        false
 31→    }
 32→
 33→    fn render(&mut self, _rows: usize, cols: usize) {
 34→        let mut parts: Vec<String> = self
 35→            .counts
 36→            .iter()
 37→            .map(|(team, &(running, pending, done, failed))| {
 38→                let short = team.strip_prefix("team-").unwrap_or(team);
 39→                let indicator = if running > 0 {
 40→                    format!("{}\u{25b6}", running) // ▶
 41→                } else if pending > 0 {
 42→                    format!("{}·", pending)
 43→                } else if failed > 0 {
 44→                    format!("{}✗", failed)
 45→                } else {
 46→                    format!("{}✓", done)
 47→                };
 48→                format!("{}:{}", short, indicator)
 49→            })
 50→            .collect();
 51→
 52→        // Totals summary
 53→        let total_running: usize = self.counts.values().map(|&(r, _, _, _)| r).sum();
 54→        let total_pending: usize = self.counts.values().map(|&(_, p, _, _)| p).sum();
 55→        let total_done: usize = self.counts.values().map(|&(_, _, d, _)| d).sum();
 56→        let total_failed: usize = self.counts.values().map(|&(_, _, _, f)| f).sum();
 57→
 58→        if !parts.is_empty() {
 59→            parts.push(format!(
 60→                "| {}▶ {}· {}✓ {}✗",
 61→                total_running, total_pending, total_done, total_failed
 62→            ));
 63→        }
 64→
 65→        let mut bar = parts.join("  ");
 66→        // Truncate to available columns using char boundaries to avoid
 67→        // panicking mid-multi-byte character (▶ = 3 bytes, · = 2, ✓ = 3).
 68→        if bar.chars().count() > cols {
 69→            bar = bar.chars().take(cols).collect();
 70→        }
 71→        print!("{}", bar);
 72→    }
 73→}
 74→
 75→impl BopPlugin {
 76→    fn refresh_counts(&mut self) {
 77→        self.counts.clear();
 78→        let base = std::path::Path::new(&self.cards_dir);
 79→
 80→        let Ok(teams) = std::fs::read_dir(base)
 81→            .map_err(|e| eprintln!("[bop-plugin] failed to read cards_dir {:?}: {e}", base))
 82→        else {
 83→            return;
 84→        };
 85→
 86→        for team_entry in teams.flatten() {
 87→            let path = team_entry.path();
 88→            if !path.is_dir() {
 89→                continue;
 90→            }
 91→            let team_name = team_entry.file_name().to_string_lossy().to_string();
 92→            // Skip non-team directories (e.g. flat state dirs at root)
 93→            if ["pending", "running", "done", "merged", "failed"].contains(&team_name.as_str()) {
 94→                continue;
 95→            }
 96→
 97→            let mut running = 0usize;
 98→            let mut pending = 0usize;
 99→            let mut done = 0usize;
100→            let mut failed = 0usize;
101→
102→            for state in ["running", "pending", "done", "merged", "failed"] {
103→                let dir = path.join(state);
104→                if let Ok(cards) = std::fs::read_dir(&dir) {
105→                    let count = cards
106→                        .flatten()
107→                        .filter(|e| {
108→                            e.path()
109→                                .extension()
110→                                .map(|x| x == "bop")
111→                                .unwrap_or(false)
112→                        })
113→                        .count();
114→                    match state {
115→                        "running" => running += count,
116→                        "pending" => pending += count,
117→                        "done" | "merged" => done += count,
118→                        "failed" => failed += count,
119→                        _ => {}
120→                    }
121→                }
122→            }
123→
124→            if running > 0 || pending > 0 || done > 0 || failed > 0 {
125→                self.counts.insert(team_name, (running, pending, done, failed));
126→            }
127→        }
128→    }
129→}
