 15→pub(crate) fn fmt_tokens(n: u64) -> String {
 16→    if n >= 10_000 {
 17→        format!("{}k", n / 1000)
 18→    } else if n >= 1_000 {
 19→        format!("{:.1}k", n as f64 / 1000.0)
 20→    } else {
 21→        format!("{}", n)
 22→    }
 23→}
