 25→pub fn cmd_inspect(root: &Path, id: &str) -> anyhow::Result<()> {
 26→    let card = paths::find_card(root, id).with_context(|| format!("card not found: {}", id))?;
 27→    let state = card
 28→        .parent()
 29→        .and_then(|p| p.file_name())
 30→        .and_then(|s| s.to_str())
 31→        .unwrap_or("unknown");
 32→
 33→    println!("=== meta ({}) ===", state);
 34→    let meta = bop_core::read_meta(&card)?;
 35→    println!("{}", serde_json::to_string_pretty(&meta)?);
 36→
 37→    let spec_path = card.join("spec.md");
 38→    if spec_path.exists() {
 39→        let spec = fs::read_to_string(&spec_path)?;
 40→        println!("\n=== spec.md ===");
 41→        print!("{}", spec);
 42→        if !spec.ends_with('\n') && !spec.is_empty() {
 43→            println!();
 44→        }
 45→    }
 46→
 47→    for (label, filename) in [("stdout", "stdout.log"), ("stderr", "stderr.log")] {
 48→        let log_path = card.join("logs").join(filename);
 49→        if log_path.exists() {
 50→            let content = fs::read_to_string(&log_path)?;
 51→            let lines: Vec<&str> = content.lines().collect();
 52→            let tail_lines = if lines.len() > 20 {
 53→                &lines[lines.len() - 20..]
 54→            } else {
 55→                &lines[..]
 56→            };
 57→            println!("\n=== {} (last {} lines) ===", label, tail_lines.len());
 58→            for line in tail_lines {
 59→                println!("{}", line);
 60→            }
 61→        }
 62→    }
 63→
 64→    // Cost summary from stdout.log JSON result line
 65→    let stdout_log = card.join("logs").join("stdout.log");
 66→    if stdout_log.exists() {
 67→        if let Some(v) = parse_latest_json_line(&stdout_log) {
 68→            if let Some(usage) = v.get("usage") {
 69→                let cache_read = usage
 70→                    .get("cache_read_input_tokens")
 71→                    .and_then(|x| x.as_u64())
 72→                    .unwrap_or(0);
 73→                let cache_create = usage
 74→                    .get("cache_creation_input_tokens")
 75→                    .and_then(|x| x.as_u64())
 76→                    .unwrap_or(0);
 77→                let output = usage
 78→                    .get("output_tokens")
 79→                    .and_then(|x| x.as_u64())
 80→                    .unwrap_or(0);
 81→                let cost = v
 82→                    .get("total_cost_usd")
 83→                    .and_then(|x| x.as_f64())
 84→                    .unwrap_or(0.0);
 85→                let turns = v.get("num_turns").and_then(|x| x.as_u64()).unwrap_or(0);
 86→                println!(
 87→                    "\nCost  ${:.2}  |  cache_read {}  cache_create {}  output {}  |  {} turns",
 88→                    cost,
 89→                    fmt_tokens(cache_read),
 90→                    fmt_tokens(cache_create),
 91→                    fmt_tokens(output),
 92→                    turns,
 93→                );
 94→            }
 95→        }
 96→    }
 97→
 98→    println!("\n=== runs ({} attempts) ===", meta.runs.len());
 99→    for (idx, run) in meta.runs.iter().enumerate() {
100→        let started = if run.started_at.len() >= 19 {
101→            run.started_at[..19].to_string()
102→        } else if run.started_at.trim().is_empty() {
103→            "<unknown>".to_string()
104→        } else {
105→            run.started_at.clone()
106→        };
107→        let provider_model = match (run.provider.trim(), run.model.trim()) {
108→            ("", "") => "unknown".to_string(),
109→            ("", m) => m.to_string(),
110→            (p, "") => p.to_string(),
111→            (p, m) => format!("{}/{}", p, m),
112→        };
113→        let stage = if run.stage.trim().is_empty() {
114→            "unknown"
115→        } else {
116→            run.stage.as_str()
117→        };
118→        let outcome = if run.outcome.trim().is_empty() {
119→            "unknown"
120→        } else {
121→            run.outcome.as_str()
122→        };
123→        let duration = run
124→            .duration_s
125→            .map(|d| format!("{}s", d))
126→            .unwrap_or_else(|| "\u{2014}".to_string());
127→        let cost = run
128→            .cost_usd
129→            .map(|c| format!("${:.2}", c))
130→            .unwrap_or_else(|| "\u{2014}".to_string());
131→        println!(
132→            "  #{:<2}  {:<20}  {:<22}  {:<12}  {:<8}  {:<6}  {}",
133→            idx + 1,
134→            started,
135→            provider_model,
136→            stage,
137→            outcome,
138→            duration,
139→            cost
140→        );
141→    }
142→
143→    Ok(())
144→}
