 2→///
 3→/// Provides both hex colors (for HTML/SVG) and ANSI terminal colors
 4→/// for consistent state visualization across commands.
 5→/// Hex color code for a given state (for HTML/SVG rendering).
 6→pub fn state_color(state: &str) -> &'static str {
 7→    match state {
 8→        "pending" => "#3A5A8A",
 9→        "running" => "#B8690F",
10→        "done" => "#1E8A45",
11→        "failed" => "#C43030",
12→        "merged" => "#6B3DB8",
13→        _ => "#555",
14→    }
15→}
16→
17→/// ANSI 256-color foreground code for a given state.
18→pub fn state_ansi(state: &str) -> &'static str {
19→    match state {
20→        "pending" => "\x1b[38;5;67m",  // steel blue
21→        "running" => "\x1b[38;5;172m", // amber
