23→fn parse_ts(s: &str) -> Option<DateTime<Utc>> {
24→    // Try standard ISO, then strip Z and retry
25→    if let Ok(dt) = s.parse::<DateTime<Utc>>() {
26→        return Some(dt);
27→    }
28→    // chrono's parse with flexible format
29→    chrono::NaiveDateTime::parse_from_str(s.trim_end_matches('Z'), "%Y-%m-%dT%H:%M:%S")
30→        .ok()
31→        .map(|n| n.and_utc())
32→}
