  1→/// Terminal capability detection for progressive rendering.
  2→///
  3→/// Detects terminal color support and dimensions to select the appropriate
  4→/// card layout: Dumb → Basic → Extended → Full → TrueColor.
  5→/// Width is re-queried on every render (never cached) so that resize events
  6→/// are picked up immediately (e.g. `bop status --watch` in a Zellij pane).
  7→use terminal_size::{terminal_size, Width};
  8→
  9→/// Terminal capability level, ordered for comparison.
 10→/// Higher levels are strictly more capable than lower ones.
 11→#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
 12→pub enum TermLevel {
 13→    /// TERM=dumb or unset; no color, ASCII only.
 14→    Dumb,
 15→    /// 8-color ANSI; ASCII borders.
 16→    Basic,
 17→    /// 16-color; box-drawing (single line); unicode blocks.
 18→    Extended,
 19→    /// 256-color; block shading ░▒▓; full BMP unicode.
 20→    Full,
 21→    /// 24-bit RGB; double-line box ╔═╗; playing-card tokens.
 22→    TrueColor,
 23→}
 24→
 25→/// Detected terminal capabilities for a single render frame.
 26→pub struct TermCaps {
 27→    pub level: TermLevel,
 28→    pub width: u16,
 29→    /// Whether two-column layout is feasible (width ≥ 100).
 30→    pub two_column: bool,
 31→}
 32→
 33→impl TermCaps {
 34→    /// Detect terminal capabilities from environment and ioctl.
 35→    ///
 36→    /// Re-call on every render — width is never cached.
 37→    pub fn detect() -> Self {
 38→        let level = Self::detect_level();
 39→        let width = terminal_size().map(|(Width(w), _)| w).unwrap_or(80);
 40→        TermCaps {
 41→            level,
 42→            width,
 43→            two_column: width >= 100,
 44→        }
 45→    }
 46→
 47→    /// Classify terminal color/glyph support from environment variables.
 48→    ///
 49→    /// Detection order:
 50→    /// 1. ZELLIJ env set → Full
 51→    /// 2. COLORTERM = truecolor | 24bit → TrueColor
 52→    /// 3. TERM contains "256color" → Full
 53→    /// 4. TERM starts with xterm/screen/tmux/rxvt → Extended
 54→    /// 5. TERM = "dumb" or empty → Dumb
 55→    /// 6. Otherwise → Basic
 56→    fn detect_level() -> TermLevel {
 57→        // Zellij always supports Full (256-color + unicode).
 58→        if std::env::var("ZELLIJ").is_ok() {
 59→            return TermLevel::Full;
 60→        }
 61→
 62→        let colorterm = std::env::var("COLORTERM").unwrap_or_default();
 63→        if colorterm == "truecolor" || colorterm == "24bit" {
 64→            return TermLevel::TrueColor;
 65→        }
 66→
 67→        let term = std::env::var("TERM").unwrap_or_default();
 68→        if term.contains("256color") {
 69→            return TermLevel::Full;
 70→        }
 71→        if term.starts_with("xterm")
 72→            || term.starts_with("screen")
 73→            || term.starts_with("tmux")
 74→            || term.starts_with("rxvt")
 75→        {
 76→            return TermLevel::Extended;
 77→        }
 78→        if term == "dumb" || term.is_empty() {
 79→            return TermLevel::Dumb;
 80→        }
 81→
 82→        TermLevel::Basic
 83→    }
 84→}
