 92→    fn detect_with_env(vars: &[(&str, &str)]) -> TermLevel {
 93→        // Save originals
 94→        let saved: Vec<(String, Option<String>)> = ["ZELLIJ", "COLORTERM", "TERM"]
 95→            .iter()
