100→        std::env::remove_var("ZELLIJ");
101→        std::env::remove_var("COLORTERM");
102→        std::env::remove_var("TERM");
103→
104→        // Apply overrides
105→        for (k, v) in vars {
106→            std::env::set_var(k, v);
107→        }
108→
109→        let result = TermCaps::detect_level();
110→
111→        // Restore originals
112→        for (k, orig) in &saved {
113→            match orig {
114→                Some(v) => std::env::set_var(k, v),
115→                None => std::env::remove_var(k),
116→            }
117→        }
118→
119→        result
120→    }
