 1→/// Shared color constants for bop CLI output.
 2→///
 3→/// Provides both hex colors (for HTML/SVG) and ANSI terminal colors
 4→/// for consistent state visualization across commands.
 5→/// Hex color code for a given state (for HTML/SVG rendering).
 6→pub fn state_color(state: &str) -> &'static str {
 7→    match state {
 8→        "pending" => "#3A5A8A",
 9→        "running" => "#B8690F",
10→        "done" => "#1E8A45",
11→        "failed" => "#C43030",
12→        "merged" => "#6B3DB8",
13→        _ => "#555",
14→    }
15→}
16→
17→/// ANSI 256-color foreground code for a given state.
18→pub fn state_ansi(state: &str) -> &'static str {
19→    match state {
20→        "pending" => "\x1b[38;5;67m",  // steel blue
21→        "running" => "\x1b[38;5;172m", // amber
22→        "done" => "\x1b[38;5;71m",     // green
23→        "failed" => "\x1b[38;5;160m",  // red
24→        "merged" => "\x1b[38;5;134m",  // violet
25→        _ => "\x1b[38;5;240m",         // gray
26→    }
27→}
28→
29→/// ANSI 256-color background code for a given state (for bar fill).
30→pub fn state_ansi_bg(state: &str) -> &'static str {
31→    match state {
32→        "pending" => "\x1b[48;5;67m",
33→        "running" => "\x1b[48;5;172m",
34→        "done" => "\x1b[48;5;71m",
35→        "failed" => "\x1b[48;5;160m",
36→        "merged" => "\x1b[48;5;134m",
