     1→/// Level 0 — Dumb renderer (no color, ASCII only).
     2→///
     3→/// Used when TERM=dumb or unset. Pure ASCII, no escape sequences.
     4→use super::{CardRenderer, CardView, Stats};
     5→
     6→pub struct DumbRenderer;
     7→
     8→impl CardRenderer for DumbRenderer {
     9→    fn render_section_header(&self, label: &str, count: usize) -> String {
    10→        format!("=== {} ({}) ===", label.to_uppercase(), count)
    11→    }
    12→
    13→    fn render_card_row(&self, card: &CardView) -> String {
    14→        let marker = match card.state.as_str() {
    15→            "running" => "[>]",
    16→            "done" | "merged" => "[x]",
    17→            "failed" => "[!]",
    18→            _ => "[ ]",
    19→        };
    20→
    21→        let mut parts = vec![format!("{} {}", marker, card.title)];
    22→
    23→        if let Some(ref provider) = card.provider {
    24→            parts.push(provider.clone());
    25→        }
    26→
    27→        if let Some(elapsed) = card.elapsed_s {
    28→            parts.push(format_duration(elapsed));
    29→        }
    30→
    31→        if card.progress > 0 {
    32→            parts.push(format!("{}%", card.progress));
    33→        }
    34→
    35→        if let Some(code) = card.exit_code {
    36→            if card.state == "failed" {
    37→                parts.push(format!("exit {}", code));
    38→            }
    39→        }
    40→
    41→        parts.join("  ")
    42→    }
    43→
    44→    fn render_progress(&self, pct: u8, phase: Option<&str>, _phase_frac: f32) -> String {
    45→        let bar_width = 10;
    46→        let filled = (pct as usize * bar_width) / 100;
    47→        let empty = bar_width - filled;
    48→
    49→        let bar = format!(
    50→            "[{}{}] {}%",
    51→            "=".repeat(filled),
    52→            " ".repeat(empty),
    53→            pct,
    54→        );
    55→
    56→        if let Some(phase) = phase {
    57→            format!("  {}  {}", bar, phase)
    58→        } else {
    59→            format!("  {}", bar)
    60→        }
    61→    }
    62→
    63→    fn render_footer(&self, stats: &Stats) -> String {
    64→        let mut parts = vec![format!("{} total", stats.total)];
    65→
    66→        if let Some(rate) = stats.success_rate_pct {
    67→            parts.push(format!("{:.0}% success", rate));
    68→        }
    69→
    70→        if let Some(avg) = stats.avg_duration_s {
    71→            parts.push(format!("avg {}", format_duration(avg as u64)));
    72→        }
    73→
    74→        parts.join(" | ")
    75→    }
    76→}
    77→
    78→/// Format seconds into human-readable "Xm Ys" or "Xs".
    79→fn format_duration(secs: u64) -> String {
    80→    if secs >= 60 {
    81→        format!("{}m{:02}s", secs / 60, secs % 60)
    82→    } else {
    83→        format!("{}s", secs)
    84→    }
    85→}
