 32→/// Calculate statistics: count cards by state and compute average duration.
 33→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
 34→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
 35→    let mut by_state = HashMap::new();
 36→    let mut total = 0;
 37→    let mut durations = Vec::new();
 38→
 39→    for state in &states {
 40→        // Process root-level state directory
 41→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
 42→
 43→        // Process team-* directories
 44→        if let Ok(entries) = fs::read_dir(root) {
 45→            for entry in entries.flatten() {
 46→                let team_path = entry.path();
 47→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
 48→                    collect_state_stats(
 49→                        &team_path,
 50→                        state,
 51→                        &mut by_state,
 52→                        &mut total,
 53→                        &mut durations,
 54→                    )?;
 55→                }
 56→            }
 57→        }
 58→    }
 59→
 60→    let avg_duration_s = if durations.is_empty() {
 61→        None
 62→    } else {
 63→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
 64→    };
 65→
 66→    let success_rate_pct = {
 67→        let done = by_state.get("done").copied().unwrap_or(0);
 68→        let failed = by_state.get("failed").copied().unwrap_or(0);
 69→        if done + failed > 0 {
 70→            Some((done as f64 / (done + failed) as f64) * 100.0)
 71→        } else {
 72→            None
 73→        }
 74→    };
 75→
 76→    Ok(CardStats {
 77→        total,
 78→        by_state,
 79→        avg_duration_s,
 80→        success_rate_pct,
 81→    })
 82→}
