 51→pub fn acquire_dispatcher_lock(cards_dir: &Path) -> anyhow::Result<DispatcherLockGuard> {
 52→    let lock_dir = cards_dir.join(DISPATCHER_LOCK_REL);
 53→    if let Some(parent) = lock_dir.parent() {
 54→        fs::create_dir_all(parent)?;
 55→    }
 56→
 57→    let owner = DispatcherLockOwner {
 58→        pid: std::process::id() as i32,
 59→        host: util::host_name(),
 60→        started_at: Utc::now(),
 61→    };
 62→    let owner_json = serde_json::to_vec_pretty(&owner)?;
 63→
 64→    for _ in 0..2 {
 65→        match fs::create_dir(&lock_dir) {
 66→            Ok(()) => {
 67→                if let Err(err) = fs::write(lock_owner_path(&lock_dir), &owner_json) {
 68→                    let _ = fs::remove_dir_all(&lock_dir);
 69→                    return Err(err.into());
 70→                }
 71→                return Ok(DispatcherLockGuard { path: lock_dir });
 72→            }
 73→            Err(err) if err.kind() == ErrorKind::AlreadyExists => {
 74→                let lock_owner = fs::read(lock_owner_path(&lock_dir))
 75→                    .ok()
 76→                    .and_then(|bytes| serde_json::from_slice::<DispatcherLockOwner>(&bytes).ok());
 77→
 78→                let stale = lock_owner
 79→                    .as_ref()
 80→                    .map(|o| !util::pid_is_alive_sync(o.pid))
 81→                    .unwrap_or(true);
 82→                if stale {
 83→                    let _ = fs::remove_dir_all(&lock_dir);
 84→                    continue;
 85→                }
 86→
 87→                if let Some(owner) = lock_owner {
 88→                    anyhow::bail!(
 89→                        "dispatcher lock already held by pid {} on {} (started {})",
 90→                        owner.pid,
 91→                        owner.host,
 92→                        owner.started_at
 93→                    );
 94→                }
 95→                anyhow::bail!(
 96→                    "dispatcher lock already exists at {}; remove stale lock if no dispatcher is running",
 97→                    lock_dir.display()
 98→                );
 99→            }
