 61→pub fn cmd_poker_submit(
 62→    root: &Path,
 63→    id: &str,
 64→    glyph: Option<&str>,
 65→    name: Option<&str>,
 66→) -> anyhow::Result<()> {
 67→    let card = paths::find_card(root, id).with_context(|| format!("card not found: {}", id))?;
 68→    let mut meta = bop_core::read_meta(&card)?;
 69→    if meta.poker_round.as_deref() != Some("open") {
