 74→        .or_else(|| std::env::var("USER").ok())
 75→        .unwrap_or_else(|| "anonymous".into());
 76→
 77→    let chosen = if let Some(g) = glyph {
 78→        g.to_owned()
 79→    } else {
 80→        // Simple fallback: prompt for glyph when no TTY picker available
 81→        eprint!("Enter glyph (e.g. 🂻): ");
 82→        let mut line = String::new();
 83→        std::io::stdin().read_line(&mut line)?;
 84→        line.trim().to_owned()
 85→    };
 86→
 87→    if chosen.is_empty() {
 88→        anyhow::bail!("no glyph provided");
 89→    }
 90→    meta.estimates.insert(participant.clone(), chosen);
 91→    write_meta(&card, &meta)?;
