     1→/// Card rendering with progressive terminal degradation.
     2→///
     3→/// Selects layout based on [`TermLevel`]: Dumb (ASCII) through TrueColor
     4→/// (double-line box, RGB gradient). The caller assembles [`CardView`] from
     5→/// `Meta` + optional AC plan data; renderers never read files.
     6→use std::collections::HashMap;
     7→
     8→use bop_core::Meta;
     9→
    10→use crate::termcaps::{TermCaps, TermLevel};
    11→
    12→mod basic;
    13→mod dumb;
    14→mod extended;
    15→mod full;
    16→mod truecolor;
    17→
    18→// ── Data structs ────────────────────────────────────────────────────────────
    19→
    20→/// Flat view struct built from `Meta` + optional AC plan data.
    21→/// The renderer operates on this — no filesystem access needed.
    22→#[derive(Debug, Clone)]
    23→pub struct CardView {
    24→    pub id: String,
    25→    pub state: String,
    26→    /// SMP playing-card glyph (U+1F0xx) — may be absent on older cards.
    27→    pub glyph: Option<String>,
    28→    /// BMP-safe suit+rank token (e.g. "♠A") for terminals that lack SMP.
    29→    pub token: Option<String>,
    30→    /// Human-readable title (falls back to `id`).
    31→    pub title: String,
    32→    /// Current pipeline stage (e.g. "implement", "qa").
    33→    pub stage: String,
    34→    /// Priority rank: 1=Urgent .. 4=Low; None = unset.
    35→    pub priority: Option<i64>,
    36→    /// Overall completion 0–100.
    37→    pub progress: u8,
    38→    /// Provider from the most recent run (e.g. "claude", "codex").
    39→    pub provider: Option<String>,
    40→    /// Wall-clock seconds from the most recent run.
    41→    pub elapsed_s: Option<u64>,
    42→    /// AC plan phase name (from `implementation_plan.json`).
    43→    pub phase_name: Option<String>,
    44→    /// Progress fraction within the current phase (0.0–1.0).
    45→    pub phase_frac: f32,
    46→    /// Human-readable failure reason (set on failed cards).
    47→    pub failure_reason: Option<String>,
    48→    /// Process exit code from the last run.
    49→    pub exit_code: Option<i32>,
    50→}
    51→
    52→/// Summary statistics for the rendered board.
    53→#[derive(Debug, Clone)]
    54→pub struct Stats {
    55→    pub total: usize,
    56→    pub by_state: HashMap<String, usize>,
    57→    pub avg_duration_s: Option<f64>,
    58→    pub success_rate_pct: Option<f64>,
    59→}
    60→
    61→// ── Renderer trait ──────────────────────────────────────────────────────────
    62→
    63→/// Trait implemented by each terminal-level renderer (dumb through truecolor).
    64→pub trait CardRenderer {
    65→    /// Section header line for a state group (e.g. "=== RUNNING (2) ===").
    66→    fn render_section_header(&self, label: &str, count: usize) -> String;
    67→
    68→    /// One row per card in the listing.
    69→    fn render_card_row(&self, card: &CardView) -> String;
    70→
    71→    /// Progress bar with optional phase annotation.
    72→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String;
    73→
    74→    /// Footer with summary statistics.
    75→    fn render_footer(&self, stats: &Stats) -> String;
    76→}
    77→
    78→// ── Conversion ──────────────────────────────────────────────────────────────
    79→
    80→/// Build a [`CardView`] from a [`Meta`] and its filesystem state directory name.
    81→///
    82→/// Fields not available from `Meta` (e.g. `phase_name`, `phase_frac`) are set
    83→/// to defaults — the caller may enrich them from AC plan data afterward.
    84→pub fn from_meta(meta: &Meta, state: &str) -> CardView {
    85→    let last_run = meta.runs.last();
    86→
    87→    CardView {
    88→        id: meta.id.clone(),
    89→        state: state.to_string(),
    90→        glyph: meta.glyph.clone(),
    91→        token: meta.token.clone(),
    92→        title: meta
    93→            .title
    94→            .clone()
    95→            .unwrap_or_else(|| meta.id.clone()),
    96→        stage: meta.stage.clone(),
    97→        priority: meta.priority,
    98→        progress: meta.progress.unwrap_or(0),
    99→        provider: last_run.map(|r| r.provider.clone()).filter(|s| !s.is_empty()),
   100→        elapsed_s: last_run.and_then(|r| r.duration_s),
   101→        phase_name: None,
   102→        phase_frac: 0.0,
   103→        failure_reason: meta.failure_reason.clone(),
   104→        exit_code: meta.exit_code,
   105→    }
   106→}
   107→
   108→// ── Board dispatch ──────────────────────────────────────────────────────────
   109→
   110→/// Render a full board to a `String`, selecting the renderer by [`TermLevel`].
   111→///
   112→/// `views` is a list of `(section_label, cards)` pairs — one per state group.
   113→/// Width is re-queried from `caps` on every call (never cached).
   114→pub fn render_board(
   115→    caps: &TermCaps,
   116→    views: &[(String, Vec<CardView>)],
   117→    stats: &Stats,
   118→) -> String {
   119→    let renderer: Box<dyn CardRenderer> = select_renderer(caps);
   120→    let mut out = String::new();
   121→
   122→    for (i, (label, cards)) in views.iter().enumerate() {
   123→        out.push_str(&renderer.render_section_header(label, cards.len()));
   124→        out.push('\n');
   125→
   126→        for card in cards {
   127→            out.push_str(&renderer.render_card_row(card));
   128→            out.push('\n');
   129→
   130→            if card.progress > 0 || card.phase_name.is_some() {
   131→                out.push_str(&renderer.render_progress(
   132→                    card.progress,
   133→                    card.phase_name.as_deref(),
   134→                    card.phase_frac,
   135→                ));
   136→                out.push('\n');
   137→            }
   138→        }
   139→
   140→        // Blank line between sections (but not after the last).
   141→        if i < views.len() - 1 {
   142→            out.push('\n');
   143→        }
   144→    }
   145→
   146→    out.push_str(&renderer.render_footer(stats));
   147→    out.push('\n');
   148→
   149→    out
   150→}
   151→
   152→/// Pick the concrete renderer for the detected terminal level.
   153→fn select_renderer(caps: &TermCaps) -> Box<dyn CardRenderer> {
   154→    match caps.level {
   155→        TermLevel::Dumb => Box::new(dumb::DumbRenderer),
   156→        TermLevel::Basic => Box::new(basic::BasicRenderer),
   157→        TermLevel::Extended => Box::new(extended::ExtendedRenderer { width: caps.width }),
   158→        TermLevel::Full => Box::new(full::FullRenderer { width: caps.width }),
   159→        TermLevel::TrueColor => Box::new(truecolor::TrueColorRenderer {
   160→            width: caps.width,
   161→            two_column: caps.two_column,
   162→        }),
   163→    }
   164→}
