 10→struct Bar {
 11→    id: String,
 12→    glyph: String,
 13→    state: String,
 14→    stage: String,
 15→    provider: String,
 16→    start: DateTime<Utc>,
 17→    end: DateTime<Utc>,
 18→    dur_s: f64,
 19→    tokens: Option<u64>,
 20→    cost: Option<f64>,
 21→}
 22→
 23→fn parse_ts(s: &str) -> Option<DateTime<Utc>> {
 24→    // Try standard ISO, then strip Z and retry
 25→    if let Ok(dt) = s.parse::<DateTime<Utc>>() {
 26→        return Some(dt);
 27→    }
 28→    // chrono's parse with flexible format
 29→    chrono::NaiveDateTime::parse_from_str(s.trim_end_matches('Z'), "%Y-%m-%dT%H:%M:%S")
 30→        .ok()
 31→        .map(|n| n.and_utc())
 32→}
 33→
 34→fn collect_bars(root: &Path) -> Vec<Bar> {
 35→    let states = ["running", "done", "merged", "failed", "pending"];
 36→    let mut bars = Vec::new();
 37→
 38→    for state in &states {
 39→        let dir = root.join(state);
 40→        if !dir.exists() {
 41→            continue;
 42→        }
 43→        let Ok(entries) = fs::read_dir(&dir) else {
 44→            continue;
 45→        };
 46→        for entry in entries.flatten() {
 47→            let path = entry.path();
 48→            if path.extension().and_then(|e| e.to_str()) != Some("bop") {
 49→                continue;
 50→            }
 51→            let Ok(meta) = bop_core::read_meta(&path) else {
 52→                continue;
 53→            };
 54→            let Some(last_run) = meta.runs.last() else {
 55→                continue;
 56→            };
 57→            let Some(start) = parse_ts(&last_run.started_at) else {
 58→                continue;
 59→            };
 60→
 61→            let end = last_run
 62→                .ended_at
 63→                .as_deref()
 64→                .and_then(parse_ts)
 65→                .unwrap_or_else(|| {
 66→                    // Cap open-ended: use duration_s or 10 min
 67→                    let dur = last_run.duration_s.unwrap_or(0) as i64;
 68→                    if dur > 0 {
 69→                        start + Duration::seconds(dur)
 70→                    } else {
 71→                        start + Duration::minutes(10)
 72→                    }
 73→                });
 74→
 75→            let dur_s = (end - start).num_milliseconds() as f64 / 1000.0;
 76→            if dur_s < 2.0 {
 77→                continue;
 78→            }
 79→
 80→            let tokens = match (last_run.prompt_tokens, last_run.completion_tokens) {
 81→                (Some(p), Some(c)) => Some(p + c),
 82→                (Some(p), None) => Some(p),
 83→                (None, Some(c)) => Some(c),
 84→                _ => None,
 85→            };
 86→
 87→            bars.push(Bar {
 88→                id: meta.id.clone(),
 89→                glyph: meta.glyph.or(meta.token).unwrap_or_default(),
 90→                state: state.to_string(),
 91→                stage: meta.stage.clone(),
 92→                provider: last_run.provider.clone(),
 93→                start,
 94→                end,
 95→                dur_s,
 96→                tokens,
 97→                cost: last_run.cost_usd,
 98→            });
 99→        }
100→    }

     1→/// Level 0 — Dumb renderer (no color, ASCII only).
     2→///
     3→/// Used when TERM=dumb or unset. Pure ASCII, no escape sequences.
     4→use super::{CardRenderer, CardView, Stats};
     5→
     6→pub struct DumbRenderer;
     7→
     8→impl CardRenderer for DumbRenderer {
     9→    fn render_section_header(&self, label: &str, count: usize) -> String {
    10→        format!("=== {} ({}) ===", label.to_uppercase(), count)
    11→    }
    12→
    13→    fn render_card_row(&self, card: &CardView) -> String {
    14→        let marker = match card.state.as_str() {
    15→            "running" => "[>]",
    16→            "done" | "merged" => "[x]",
    17→            "failed" => "[!]",
    18→            _ => "[ ]",
    19→        };
    20→
    21→        let mut parts = vec![format!("{} {}", marker, card.title)];
    22→
    23→        if let Some(ref provider) = card.provider {
    24→            parts.push(provider.clone());
    25→        }
    26→
    27→        if let Some(elapsed) = card.elapsed_s {
    28→            parts.push(format_duration(elapsed));
    29→        }
    30→
    31→        if card.progress > 0 {
    32→            parts.push(format!("{}%", card.progress));
    33→        }
    34→
    35→        if let Some(code) = card.exit_code {
    36→            if card.state == "failed" {
    37→                parts.push(format!("exit {}", code));
    38→            }
    39→        }
    40→
    41→        parts.join("  ")
    42→    }
    43→
    44→    fn render_progress(&self, pct: u8, phase: Option<&str>, _phase_frac: f32) -> String {
    45→        let bar_width = 10;
    46→        let filled = (pct as usize * bar_width) / 100;
    47→        let empty = bar_width - filled;
    48→
    49→        let bar = format!(
    50→            "[{}{}] {}%",
    51→            "=".repeat(filled),
    52→            " ".repeat(empty),
    53→            pct,
    54→        );
    55→
    56→        if let Some(phase) = phase {
    57→            format!("  {}  {}", bar, phase)
    58→        } else {
    59→            format!("  {}", bar)
    60→        }
    61→    }
    62→
    63→    fn render_footer(&self, stats: &Stats) -> String {
    64→        let mut parts = vec![format!("{} total", stats.total)];
    65→
    66→        if let Some(rate) = stats.success_rate_pct {
    67→            parts.push(format!("{:.0}% success", rate));
    68→        }
    69→
    70→        if let Some(avg) = stats.avg_duration_s {
    71→            parts.push(format!("avg {}", format_duration(avg as u64)));
    72→        }
    73→
    74→        parts.join(" | ")
    75→    }
    76→}
    77→
    78→/// Format seconds into human-readable "Xm Ys" or "Xs".
    79→fn format_duration(secs: u64) -> String {
    80→    if secs >= 60 {
    81→        format!("{}m{:02}s", secs / 60, secs % 60)
    82→    } else {
    83→        format!("{}s", secs)
    84→    }
    85→}
