    15→fn resolve_states(state_filter: &str) -> Vec<&str> {
    16→    match state_filter {
    17→        "all" => vec!["drafts", "pending", "running", "done", "failed", "merged"],
    18→        "active" => vec!["pending", "running", "done"],
