    24→/// Summary statistics for cards in the workspace.
    25→pub struct CardStats {
    26→    pub total: usize,
    27→    pub by_state: HashMap<String, usize>,
    28→    pub avg_duration_s: Option<f64>,
    29→    pub success_rate_pct: Option<f64>,
    30→}
    31→
    32→/// Calculate statistics: count cards by state and compute average duration.
    33→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    34→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    35→    let mut by_state = HashMap::new();
    36→    let mut total = 0;
    37→    let mut durations = Vec::new();
    38→
    39→    for state in &states {
    40→        // Process root-level state directory
    41→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    42→
    43→        // Process team-* directories
    44→        if let Ok(entries) = fs::read_dir(root) {
    45→            for entry in entries.flatten() {
    46→                let team_path = entry.path();
    47→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    48→                    collect_state_stats(
    49→                        &team_path,
    50→                        state,
    51→                        &mut by_state,
    52→                        &mut total,
    53→                        &mut durations,
    54→                    )?;
    55→                }
    56→            }
    57→        }
    58→    }
    59→
    60→    let avg_duration_s = if durations.is_empty() {
    61→        None
    62→    } else {
    63→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    64→    };
    65→
    66→    let success_rate_pct = {
    67→        let done = by_state.get("done").copied().unwrap_or(0);
    68→        let failed = by_state.get("failed").copied().unwrap_or(0);
    69→        if done + failed > 0 {
    70→            Some((done as f64 / (done + failed) as f64) * 100.0)
    71→        } else {
    72→            None
    73→        }
    74→    };
    75→
    76→    Ok(CardStats {
    77→        total,
    78→        by_state,
    79→        avg_duration_s,
    80→        success_rate_pct,
    81→    })
    82→}
    83→
    84→fn collect_state_stats(
    85→    dir: &Path,
    86→    state: &str,
    87→    by_state: &mut HashMap<String, usize>,
    88→    total: &mut usize,
    89→    durations: &mut Vec<f64>,
    90→) -> anyhow::Result<()> {
    91→    let state_dir = dir.join(state);
    92→    if !state_dir.exists() {
    93→        return Ok(());
    94→    }
    95→
    96→    let Ok(entries) = fs::read_dir(&state_dir) else {
    97→        return Ok(());
    98→    };
    99→
   100→    for entry in entries.flatten() {
   101→        let path = entry.path();
   102→        if path.is_dir()
   103→            && path
   104→                .extension()
   105→                .is_some_and(|e| e == "bop" || e == "jobcard")
   106→        {
   107→            if let Ok(meta) = bop_core::read_meta(&path) {
   108→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   109→                *total += 1;
   110→
   111→                // Collect duration from last run if available
   112→                if let Some(last_run) = meta.runs.last() {
   113→                    if let Some(dur) = last_run.duration_s {
   114→                        durations.push(dur as f64);
   115→                    }
   116→                }
   117→            }
   118→        }
   119→    }
   120→
   121→    Ok(())
   122→}
