   163→/// Count how many lines will be printed by list_cards() for cursor positioning.
   164→fn count_display_lines(root: &Path, state_filter: &str) -> anyhow::Result<usize> {
   165→    let states = resolve_states(state_filter);
   166→    let mut line_count = 0;
   167→
   168→    for (i, state) in states.iter().enumerate() {
   169→        // Count root-level state group lines
   170→        line_count += count_state_group_lines(root, state)?;
   171→
   172→        // Count team-* directories
   173→        if let Ok(entries) = fs::read_dir(root) {
   174→            let mut team_dirs: Vec<_> = entries
