   178→                    let s = name.to_string_lossy();
   179→                    e.path().is_dir() && s.starts_with("team-")
   180→                })
   181→                .collect();
   182→            team_dirs.sort_by_key(|e| e.file_name());
   183→            for entry in team_dirs {
   184→                line_count += count_state_group_lines(&entry.path(), state)?;
   185→            }
   186→        }
   187→
   188→        // Add separator between state groups (but not after the last one)
   189→        if i < states.len() - 1 {
   190→            line_count += 1; // separator line
   191→        }
   192→    }
   193→
   194→    // Final separator and summary
   195→    line_count += 1; // separator before summary
