   201→/// Count lines for a single state group (header + cards + blank line).
   202→fn count_state_group_lines(dir: &Path, state: &str) -> anyhow::Result<usize> {
   203→    let state_dir = dir.join(state);
   204→    if !state_dir.exists() {
   205→        return Ok(0);
   206→    }
   207→
   208→    let mut card_count = 0;
   209→    if let Ok(entries) = fs::read_dir(&state_dir) {
   210→        for entry in entries.flatten() {
   211→            let p = entry.path();
   212→            if p.is_dir()
   213→                && p.extension().is_some_and(|e| e == "bop" || e == "jobcard")
   214→                && bop_core::read_meta(&p).is_ok()
   215→            {
   216→                card_count += 1;
   217→            }
   218→        }
   219→    }
   220→
   221→    if card_count == 0 {
   222→        return Ok(0);
   223→    }
   224→
   225→    // header + cards + blank line
   226→    Ok(1 + card_count + 1)
   227→}
