   236→/// Watch for filesystem changes and continuously redraw the card list.
   237→/// This function sets up watchers on all state directories and redraws
   238→/// the display whenever cards are added, removed, or modified.
   239→pub async fn list_cards_watch(root: &Path, state_filter: &str) -> anyhow::Result<()> {
   240→    // Singleton guard — only one watch instance per cards dir.
   241→    // Uses mkdir-atomicity (same pattern as dispatcher lock).
   242→    // Guard is held for the lifetime of the function; Drop removes the lock dir.
   243→    let _watch_lock = lock::acquire_watch_lock(root).map_err(|e| {
   244→        eprintln!("{}", e);
   245→        e
   246→    })?;
   247→
   248→    // Collect all state directories to watch
   249→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
   250→    let mut watch_dirs = Vec::new();
   251→
   252→    // Add root-level state directories
   253→    for state in &states {
   254→        let state_dir = root.join(state);
