206→/// Count how many lines will be printed by list_cards() for cursor positioning.
207→fn count_display_lines(root: &Path, state_filter: &str) -> anyhow::Result<usize> {
208→    let states = resolve_states(state_filter);
209→    let mut line_count = 0;
210→
211→    for (i, state) in states.iter().enumerate() {
212→        // Count root-level state group lines
213→        line_count += count_state_group_lines(root, state)?;
214→
215→        // Count team-* directories
216→        if let Ok(entries) = fs::read_dir(root) {
217→            let mut team_dirs: Vec<_> = entries
218→                .flatten()
219→                .filter(|e| {
220→                    let name = e.file_name();
221→                    let s = name.to_string_lossy();
222→                    e.path().is_dir() && s.starts_with("team-")
223→                })
224→                .collect();
225→            team_dirs.sort_by_key(|e| e.file_name());
226→            for entry in team_dirs {
227→                line_count += count_state_group_lines(&entry.path(), state)?;
228→            }
229→        }
230→
231→        // Add separator between state groups (but not after the last one)
232→        if i < states.len() - 1 {
233→            line_count += 1; // separator line
234→        }
235→    }
236→
237→    // Final separator and summary
238→    line_count += 1; // separator before summary
239→    line_count += 1; // summary line
240→
241→    Ok(line_count)
242→}
243→
244→/// Count lines for a single state group (header + cards + blank line).
245→fn count_state_group_lines(dir: &Path, state: &str) -> anyhow::Result<usize> {
246→    let state_dir = dir.join(state);
247→    if !state_dir.exists() {
248→        return Ok(0);
249→    }
250→
251→    let mut card_count = 0;
252→    if let Ok(entries) = fs::read_dir(&state_dir) {
253→        for entry in entries.flatten() {
254→            let p = entry.path();
255→            if p.is_dir()
256→                && p.extension().is_some_and(|e| e == "bop" || e == "jobcard")
257→                && bop_core::read_meta(&p).is_ok()
258→            {
259→                card_count += 1;
260→            }
261→        }
262→    }
263→
264→    if card_count == 0 {
265→        return Ok(0);
266→    }
267→
268→    // header + cards + blank line
269→    Ok(1 + card_count + 1)
270→}
