     1→/// Level 1 — Basic renderer (8-color ANSI, ASCII borders).
     2→///
     3→/// Adds color to state labels and simple `+--+` box borders.
     4→/// Uses standard 8-color ANSI codes (30–37) with ASCII `+`, `-`, `|` borders.
     5→use crate::colors::{BOLD, DIM, RESET};
     6→
     7→use super::{CardRenderer, CardView, Stats};
     8→
     9→pub struct BasicRenderer;
    10→
    11→/// 8-color ANSI foreground code for a given state.
    12→fn state_color_8(state: &str) -> &'static str {
    13→    match state {
    14→        "pending" => "\x1b[34m", // blue
    15→        "running" => "\x1b[33m", // yellow
    16→        "done" => "\x1b[32m",    // green
    17→        "failed" => "\x1b[31m",  // red
    18→        "merged" => "\x1b[35m",  // magenta
    19→        _ => "\x1b[37m",         // white
    20→    }
    21→}
    22→
    23→/// Format seconds into human-readable "XmYYs" or "Xs".
    24→fn format_duration(secs: u64) -> String {
    25→    if secs >= 60 {
    26→        format!("{}m{:02}s", secs / 60, secs % 60)
    27→    } else {
    28→        format!("{}s", secs)
    29→    }
    30→}
    31→
    32→impl CardRenderer for BasicRenderer {
    33→    fn render_section_header(&self, label: &str, count: usize) -> String {
    34→        let color = state_color_8(label);
    35→        format!(
    36→            "{}{}+-- {} ({}) --+{}",
    37→            BOLD,
    38→            color,
    39→            label.to_uppercase(),
    40→            count,
    41→            RESET,
    42→        )
    43→    }
    44→
    45→    fn render_card_row(&self, card: &CardView) -> String {
    46→        let color = state_color_8(&card.state);
    47→
    48→        let marker = match card.state.as_str() {
    49→            "running" => format!("{}[>]{}", color, RESET),
    50→            "done" | "merged" => format!("{}[x]{}", color, RESET),
    51→            "failed" => format!("{}[!]{}", color, RESET),
    52→            _ => "[ ]".to_string(),
    53→        };
    54→
    55→        let mut parts = vec![format!("| {} {}", marker, card.title)];
    56→
    57→        if let Some(ref provider) = card.provider {
    58→            parts.push(format!("{}{}{}", DIM, provider, RESET));
    59→        }
    60→
    61→        if let Some(elapsed) = card.elapsed_s {
    62→            parts.push(format!("{}{}{}", DIM, format_duration(elapsed), RESET));
    63→        }
    64→
    65→        if card.progress > 0 {
    66→            parts.push(format!("{}%", card.progress));
    67→        }
    68→
    69→        if let Some(code) = card.exit_code {
    70→            if card.state == "failed" {
    71→                parts.push(format!("{}exit {}{}", color, code, RESET));
    72→            }
    73→        }
    74→
    75→        parts.join("  ")
    76→    }
    77→
    78→    fn render_progress(&self, pct: u8, phase: Option<&str>, _phase_frac: f32) -> String {
    79→        let bar_width = 10;
    80→        let filled = (pct as usize * bar_width) / 100;
    81→        let empty = bar_width - filled;
    82→
    83→        let bar = format!("[{}{}] {}%", "=".repeat(filled), " ".repeat(empty), pct,);
    84→
    85→        if let Some(phase) = phase {
    86→            format!("|   {}  {}", bar, phase)
    87→        } else {
    88→            format!("|   {}", bar)
    89→        }
    90→    }
    91→
    92→    fn render_footer(&self, stats: &Stats) -> String {
    93→        let mut parts = vec![format!("{} total", stats.total)];
    94→
    95→        if let Some(rate) = stats.success_rate_pct {
    96→            parts.push(format!("{:.0}% success", rate));
    97→        }
    98→
    99→        if let Some(avg) = stats.avg_duration_s {
   100→            parts.push(format!("avg {}", format_duration(avg as u64)));
   101→        }
   102→
   103→        let content = parts.join(" | ");
   104→        format!("{}+-- {} --+{}", DIM, content, RESET)
   105→    }
   106→}
