     2→///
     3→/// Section headers use `░▒▓ LABEL ▓▒░` dithered fade filled to terminal width.
     4→/// Left-accent `▌` in state color; dice glyphs ⚀⚁⚂⚃⚄⚅ encode priority P1–P6.
     5→/// Progress bar: 16-cell `████░░░░` (U+2588 filled, U+2591 empty).
     6→/// Phase name + moon quarter glyph. Footer with same dithered pattern.
     7→use crate::colors::{state_ansi, BOLD, DIM, RESET};
     8→
     9→use super::{CardRenderer, CardView, Stats};
    10→
    11→pub struct FullRenderer {
    12→    pub width: u16,
    13→}
    14→
    15→/// Dice glyph for priority 1–6: ⚀⚁⚂⚃⚄⚅.
    16→///
    17→/// Returns `None` for out-of-range or unset priority.
    18→fn dice_glyph(priority: Option<i64>) -> Option<char> {
    19→    match priority {
    20→        Some(1) => Some('⚀'),
    21→        Some(2) => Some('⚁'),
    22→        Some(3) => Some('⚂'),
    23→        Some(4) => Some('⚃'),
    24→        Some(5) => Some('⚄'),
    25→        Some(6) => Some('⚅'),
    26→        _ => None,
    27→    }
    28→}
    29→
    30→/// Moon-quarter glyph for phase progress fraction.
    31→///
    32→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    33→fn moon_glyph(frac: f32) -> char {
    34→    if frac < 0.25 {
    35→        '◔'
    36→    } else if frac < 0.50 {
    37→        '◑'
    38→    } else if frac < 0.75 {
    39→        '◕'
    40→    } else {
    41→        '●'
    42→    }
    43→}
    44→
    45→/// Format seconds into human-readable "XmYYs" or "Xs".
    46→fn format_duration(secs: u64) -> String {
    47→    if secs >= 60 {
    48→        format!("{}m{:02}s", secs / 60, secs % 60)
    49→    } else {
    50→        format!("{}s", secs)
    51→    }
    52→}
    53→
    54→/// Build a dithered header/footer line: `░▒▓ LABEL ▓▒░` + `░` fill to width.
    55→fn dithered_line(label: &str, width: usize) -> String {
    56→    let prefix = format!("░▒▓ {} ▓▒░", label);
    57→    let prefix_len = prefix.chars().count();
    58→    let fill_len = width.saturating_sub(prefix_len);
    59→    let fill = "░".repeat(fill_len);
    60→    format!("{}{}", prefix, fill)
    61→}
