    11→
    12→pub struct TrueColorRenderer {
    13→    pub width: u16,
    14→    pub two_column: bool,
    15→}
    16→
    17→// ── RGB color helpers ────────────────────────────────────────────────────────
    18→
    19→/// 24-bit RGB foreground escape sequence for a given card state.
    20→///
    21→/// Colors match the hex values in `colors::state_color()`.
    22→fn state_rgb(state: &str) -> String {
    23→    let (r, g, b) = match state {
    24→        "pending" => (0x3A, 0x5A, 0x8A),
    25→        "running" => (0xB8, 0x69, 0x0F),
    26→        "done" => (0x1E, 0x8A, 0x45),
    27→        "failed" => (0xC4, 0x30, 0x30),
    28→        "merged" => (0x6B, 0x3D, 0xB8),
    29→        _ => (0x55, 0x55, 0x55),
    30→    };
    31→    format!("\x1b[38;2;{};{};{}m", r, g, b)
    32→}
    33→
    34→/// Linear interpolation between two `u8` values at fraction `t` (clamped 0–1).
    35→fn lerp_u8(a: u8, b: u8, t: f32) -> u8 {
    36→    let t = t.clamp(0.0, 1.0);
    37→    (a as f32 + (b as f32 - a as f32) * t) as u8
    38→}
    39→
    40→/// 24-bit RGB foreground escape for a single progress-bar cell at position
    41→/// `t` (0.0 = amber, 1.0 = green).
    42→fn gradient_fg(t: f32) -> String {
    43→    // Amber #B8690F → Green #1E8A45.
    44→    let r = lerp_u8(0xB8, 0x1E, t);
    45→    let g = lerp_u8(0x69, 0x8A, t);
    46→    let b = lerp_u8(0x0F, 0x45, t);
    47→    format!("\x1b[38;2;{};{};{}m", r, g, b)
    48→}
    49→
    50→// ── Glyph helpers ────────────────────────────────────────────────────────────
    51→
    52→/// Dice glyph for priority 1–6: ⚀⚁⚂⚃⚄⚅.
    53→///
    54→/// Returns `None` for out-of-range or unset priority.
    55→fn dice_glyph(priority: Option<i64>) -> Option<char> {
    56→    match priority {
    57→        Some(1) => Some('⚀'),
    58→        Some(2) => Some('⚁'),
    59→        Some(3) => Some('⚂'),
    60→        Some(4) => Some('⚃'),
    61→        Some(5) => Some('⚄'),
    62→        Some(6) => Some('⚅'),
    63→        _ => None,
    64→    }
    65→}
    66→
    67→/// Moon-quarter glyph for phase progress fraction.
    68→///
    69→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    70→fn moon_glyph(frac: f32) -> char {
    71→    if frac < 0.25 {
    72→        '◔'
    73→    } else if frac < 0.50 {
    74→        '◑'
    75→    } else if frac < 0.75 {
    76→        '◕'
    77→    } else {
    78→        '●'
    79→    }
    80→}
    81→
    82→/// Format seconds into human-readable "XmYYs" or "Xs".
    83→fn format_duration(secs: u64) -> String {
    84→    if secs >= 60 {
    85→        format!("{}m{:02}s", secs / 60, secs % 60)
    86→    } else {
    87→        format!("{}s", secs)
    88→    }
    89→}
    90→
    91→// ── Layout helpers ───────────────────────────────────────────────────────────
    92→
    93→/// Effective column width: full terminal width in single-column mode,
    94→/// half width in two-column mode.
    95→fn col_width(width: u16, two_column: bool) -> usize {
    96→    let w = width as usize;
    97→    if two_column {
    98→        w / 2
    99→    } else {
   100→        w
   101→    }
   102→}
