     1→/// Level 3 — Full renderer (256-color, demoscene block headers).
     2→///
     3→/// Section headers use `░▒▓ LABEL ▓▒░` dithered fade filled to terminal width.
     4→/// Left-accent `▌` in state color; dice glyphs ⚀⚁⚂⚃⚄⚅ encode priority P1–P6.
     5→/// Progress bar: 16-cell `████░░░░` (U+2588 filled, U+2591 empty).
     6→/// Phase name + moon quarter glyph. Footer with same dithered pattern.
     7→use crate::colors::{state_ansi, BOLD, DIM, RESET};
     8→
     9→use super::{CardRenderer, CardView, Stats};
    10→
    11→pub struct FullRenderer {
    12→    pub width: u16,
    13→}
    14→
    15→/// Dice glyph for priority 1–6: ⚀⚁⚂⚃⚄⚅.
    16→///
    17→/// Returns `None` for out-of-range or unset priority.
    18→fn dice_glyph(priority: Option<i64>) -> Option<char> {
    19→    match priority {
    20→        Some(1) => Some('⚀'),
    21→        Some(2) => Some('⚁'),
    22→        Some(3) => Some('⚂'),
    23→        Some(4) => Some('⚃'),
    24→        Some(5) => Some('⚄'),
    25→        Some(6) => Some('⚅'),
    26→        _ => None,
    27→    }
    28→}
    29→
    30→/// Moon-quarter glyph for phase progress fraction.
    31→///
    32→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    33→fn moon_glyph(frac: f32) -> char {
    34→    if frac < 0.25 {
    35→        '◔'
    36→    } else if frac < 0.50 {
    37→        '◑'
    38→    } else if frac < 0.75 {
    39→        '◕'
    40→    } else {
    41→        '●'
    42→    }
    43→}
    44→
    45→/// Format seconds into human-readable "XmYYs" or "Xs".
    46→fn format_duration(secs: u64) -> String {
    47→    if secs >= 60 {
    48→        format!("{}m{:02}s", secs / 60, secs % 60)
    49→    } else {
    50→        format!("{}s", secs)
    51→    }
    52→}
    53→
    54→/// Build a dithered header/footer line: `░▒▓ LABEL ▓▒░` + `░` fill to width.
    55→fn dithered_line(label: &str, width: usize) -> String {
    56→    let prefix = format!("░▒▓ {} ▓▒░", label);
    57→    let prefix_len = prefix.chars().count();
    58→    let fill_len = width.saturating_sub(prefix_len);
    59→    let fill = "░".repeat(fill_len);
    60→    format!("{}{}", prefix, fill)
    61→}
    62→
    63→impl CardRenderer for FullRenderer {
    64→    fn render_section_header(&self, label: &str, count: usize) -> String {
    65→        let color = state_ansi(label);
    66→        let title = format!("{} ({})", label.to_uppercase(), count);
    67→        let w = self.width as usize;
    68→        let header = dithered_line(&title, w);
    69→        format!("{}{}{}{}", BOLD, color, header, RESET)
    70→    }
    71→
    72→    fn render_card_row(&self, card: &CardView) -> String {
    73→        let color = state_ansi(&card.state);
    74→
    75→        // Left accent stripe ▌ in state color (256-color).
    76→        let accent = format!("{}▌{}", color, RESET);
    77→
    78→        let marker = match card.state.as_str() {
    79→            "running" => format!("{}▶{}", color, RESET),
    80→            "done" | "merged" => format!("{}✓{}", color, RESET),
    81→            "failed" => format!("{}✗{}", color, RESET),
    82→            _ => "·".to_string(),
    83→        };
    84→
    85→        let mut parts = vec![format!("{} {} {}", accent, marker, card.title)];
    86→
    87→        // Dice glyph for priority.
    88→        if let Some(die) = dice_glyph(card.priority) {
    89→            parts.push(format!("{}{}{}", color, die, RESET));
    90→        }
    91→
    92→        if let Some(ref provider) = card.provider {
    93→            parts.push(format!("{}{}{}", DIM, provider, RESET));
    94→        }
    95→
    96→        if let Some(elapsed) = card.elapsed_s {
    97→            parts.push(format!("{}{}{}", DIM, format_duration(elapsed), RESET));
    98→        }
    99→
   100→        if card.progress > 0 {
   101→            parts.push(format!("{}%", card.progress));
   102→        }
   103→
   104→        if let Some(code) = card.exit_code {
   105→            if card.state == "failed" {
   106→                parts.push(format!("{}exit {}{}", color, code, RESET));
   107→            }
   108→        }
   109→
   110→        parts.join("  ")
   111→    }
   112→
   113→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String {
   114→        let bar_width = 16;
   115→        let filled = (pct as usize * bar_width) / 100;
   116→        let empty = bar_width - filled;
   117→
   118→        let bar = format!("{}{} {}%", "█".repeat(filled), "░".repeat(empty), pct,);
   119→
   120→        let phase_str = if let Some(phase) = phase {
   121→            format!("  {} {}", moon_glyph(phase_frac), phase)
   122→        } else {
   123→            String::new()
   124→        };
   125→
   126→        format!("▌   {}{}", bar, phase_str)
   127→    }
   128→
   129→    fn render_footer(&self, stats: &Stats) -> String {
   130→        let mut parts = vec![format!("{} total", stats.total)];
   131→
   132→        if let Some(rate) = stats.success_rate_pct {
   133→            parts.push(format!("{:.0}% success", rate));
   134→        }
   135→
   136→        if let Some(avg) = stats.avg_duration_s {
   137→            parts.push(format!("avg {}", format_duration(avg as u64)));
   138→        }
   139→
   140→        let content = parts.join(" │ ");
   141→        let w = self.width as usize;
   142→        let footer = dithered_line(&content, w);
   143→        format!("{}{}{}", DIM, footer, RESET)
   144→    }
   145→}
