   104→impl TrueColorRenderer {
   105→    /// Inner width available for rounded card-separator lines.
   106→    ///
   107→    /// Accounts for `║ ╭` prefix (4 columns) and `╮` suffix (1 column).
   108→    fn inner_width(&self) -> usize {
   109→        col_width(self.width, self.two_column).saturating_sub(5)
   110→    }
   111→}
   112→
   113→impl CardRenderer for TrueColorRenderer {
   114→    fn render_section_header(&self, label: &str, count: usize) -> String {
   115→        let color = state_rgb(label);
   116→        let title = format!(" {} ({}) ", label.to_uppercase(), count);
   117→        let w = col_width(self.width, self.two_column);
   118→        let inner = w.saturating_sub(2); // ╔ and ╗
   119→        let fill_len = inner.saturating_sub(title.len());
   120→        let fill = "═".repeat(fill_len);
   121→        format!("{}{}╔{}{}╗{}", BOLD, color, title, fill, RESET)
   122→    }
   123→
   124→    fn render_card_row(&self, card: &CardView) -> String {
   125→        let color = state_rgb(&card.state);
   126→        let iw = self.inner_width();
   127→
   128→        let marker = match card.state.as_str() {
   129→            "running" => format!("{}▶{}", color, RESET),
   130→            "done" | "merged" => format!("{}✓{}", color, RESET),
   131→            "failed" => format!("{}✗{}", color, RESET),
   132→            _ => "·".to_string(),
   133→        };
   134→
   135→        let mut parts = vec![format!("{} {}", marker, card.title)];
   136→
   137→        // Dice glyph for priority.
   138→        if let Some(die) = dice_glyph(card.priority) {
   139→            parts.push(format!("{}{}{}", color, die, RESET));
   140→        }
   141→
   142→        if let Some(ref provider) = card.provider {
   143→            parts.push(format!("{}{}{}", DIM, provider, RESET));
   144→        }
   145→
   146→        if let Some(elapsed) = card.elapsed_s {
   147→            parts.push(format!("{}{}{}", DIM, format_duration(elapsed), RESET));
   148→        }
   149→
   150→        if card.progress > 0 {
   151→            parts.push(format!("{}%", card.progress));
   152→        }
   153→
   154→        if let Some(code) = card.exit_code {
   155→            if card.state == "failed" {
   156→                parts.push(format!("{}exit {}{}", color, code, RESET));
   157→            }
   158→        }
   159→
   160→        let content = parts.join("  ");
   161→        let has_progress = card.progress > 0 || card.phase_name.is_some();
   162→
   163→        // Rounded card separator top + content line.
   164→        let top = format!("║ ╭{}╮", "─".repeat(iw));
   165→        let mid = format!("║ │ {}", content);
   166→
   167→        if has_progress {
   168→            // Leave rounded box open — progress bar will close it.
   169→            format!("{}\n{}", top, mid)
   170→        } else {
   171→            // Close rounded box immediately.
   172→            let bot = format!("║ ╰{}╯", "─".repeat(iw));
   173→            format!("{}\n{}\n{}", top, mid, bot)
   174→        }
   175→    }
   176→
   177→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String {
   178→        let bar_width: usize = 16;
   179→        let iw = self.inner_width();
   180→        let filled = (pct as usize * bar_width) / 100;
   181→        let empty = bar_width - filled;
   182→
   183→        // RGB gradient bar: each filled cell gets a per-cell color
