   186→/// Convert [`CardStats`] to [`render::Stats`].
   187→fn stats_to_render_stats(stats: &CardStats) -> render::Stats {
   188→    render::Stats {
   189→        total: stats.total,
   190→        by_state: stats.by_state.clone(),
   191→        avg_duration_s: stats.avg_duration_s,
   192→        success_rate_pct: stats.success_rate_pct,
   193→    }
   194→}
