     1→/// Level 2 — Extended renderer (16-color, single-line box drawing).
     2→///
     3→/// Uses `┌─┐│└─┘` borders and left-accent `▌` (U+258C) stripes in state color.
     4→/// Progress bar: `████░░░░` 16-cell (filled U+2588, empty U+2591) with percentage.
     5→/// Phase name + moon-quarter glyph (◔◑◕●) for phase progress.
     6→use crate::colors::{BOLD, DIM, RESET};
     7→
     8→use super::{CardRenderer, CardView, Stats};
     9→
    10→pub struct ExtendedRenderer {
    11→    pub width: u16,
    12→}
    13→
    14→/// 16-color ANSI foreground code for a given state (bright variants 90–97).
    15→fn state_color_16(state: &str) -> &'static str {
    16→    match state {
    17→        "pending" => "\x1b[94m", // bright blue
    18→        "running" => "\x1b[93m", // bright yellow
    19→        "done" => "\x1b[92m",    // bright green
    20→        "failed" => "\x1b[91m",  // bright red
    21→        "merged" => "\x1b[95m",  // bright magenta
    22→        _ => "\x1b[37m",         // white
    23→    }
    24→}
    25→
    26→/// Moon-quarter glyph for phase progress fraction.
    27→///
    28→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    29→fn moon_glyph(frac: f32) -> char {
    30→    if frac < 0.25 {
    31→        '◔'
    32→    } else if frac < 0.50 {
    33→        '◑'
    34→    } else if frac < 0.75 {
    35→        '◕'
    36→    } else {
    37→        '●'
    38→    }
    39→}
    40→
    41→/// Format seconds into human-readable "XmYYs" or "Xs".
    42→fn format_duration(secs: u64) -> String {
    43→    if secs >= 60 {
    44→        format!("{}m{:02}s", secs / 60, secs % 60)
    45→    } else {
    46→        format!("{}s", secs)
    47→    }
    48→}
    49→
    50→impl CardRenderer for ExtendedRenderer {
    51→    fn render_section_header(&self, label: &str, count: usize) -> String {
    52→        let color = state_color_16(label);
    53→        let title = format!(" {} ({}) ", label.to_uppercase(), count);
    54→        let w = self.width as usize;
    55→        // Account for ┌ and ┐ (1 column each).
    56→        let inner = w.saturating_sub(2);
    57→        let fill_len = inner.saturating_sub(title.len());
    58→        let fill = "─".repeat(fill_len);
    59→        format!("{}{}┌{}{}┐{}", BOLD, color, title, fill, RESET)
    60→    }
    61→
    62→    fn render_card_row(&self, card: &CardView) -> String {
    63→        let color = state_color_16(&card.state);
    64→
    65→        // Left accent stripe ▌ in state color.
    66→        let accent = format!("{}▌{}", color, RESET);
    67→
    68→        let marker = match card.state.as_str() {
    69→            "running" => format!("{}▶{}", color, RESET),
    70→            "done" | "merged" => format!("{}✓{}", color, RESET),
    71→            "failed" => format!("{}✗{}", color, RESET),
    72→            _ => "·".to_string(),
    73→        };
    74→
    75→        let mut parts = vec![format!("{} {} {}", accent, marker, card.title)];
    76→
    77→        if let Some(ref provider) = card.provider {
    78→            parts.push(format!("{}{}{}", DIM, provider, RESET));
    79→        }
    80→
    81→        if let Some(elapsed) = card.elapsed_s {
    82→            parts.push(format!("{}{}{}", DIM, format_duration(elapsed), RESET));
    83→        }
    84→
    85→        if card.progress > 0 {
    86→            parts.push(format!("{}%", card.progress));
    87→        }
    88→
    89→        if let Some(code) = card.exit_code {
    90→            if card.state == "failed" {
    91→                parts.push(format!("{}exit {}{}", color, code, RESET));
    92→            }
    93→        }
    94→
    95→        parts.join("  ")
    96→    }
    97→
    98→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String {
    99→        let bar_width = 16;
   100→        let filled = (pct as usize * bar_width) / 100;
   101→        let empty = bar_width - filled;
   102→
   103→        let bar = format!("{}{} {}%", "█".repeat(filled), "░".repeat(empty), pct,);
   104→
   105→        let phase_str = if let Some(phase) = phase {
   106→            format!("  {} {}", moon_glyph(phase_frac), phase)
   107→        } else {
   108→            String::new()
   109→        };
   110→
   111→        format!("│   {}{}", bar, phase_str)
   112→    }
   113→
   114→    fn render_footer(&self, stats: &Stats) -> String {
   115→        let mut parts = vec![format!("{} total", stats.total)];
   116→
   117→        if let Some(rate) = stats.success_rate_pct {
   118→            parts.push(format!("{:.0}% success", rate));
   119→        }
   120→
   121→        if let Some(avg) = stats.avg_duration_s {
   122→            parts.push(format!("avg {}", format_duration(avg as u64)));
   123→        }
   124→
   125→        let content = parts.join(" │ ");
   126→        let content_len = content.chars().count();
   127→        let w = self.width as usize;
   128→        // └─ content ─┘ → 4 extra chars for └─ and ─┘.
   129→        let fill_len = w.saturating_sub(content_len + 4);
   130→        let fill = "─".repeat(fill_len);
   131→        format!("{}└─ {} {}┘{}", DIM, content, fill, RESET)
   132→    }
   133→}
