 69→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
 70→fn moon_glyph(frac: f32) -> char {
 71→    if frac < 0.25 {
 72→        '◔'
 73→    } else if frac < 0.50 {
 74→        '◑'
 75→    } else if frac < 0.75 {
 76→        '◕'
 77→    } else {
 78→        '●'
 79→    }
 80→}
